package com.fantasyfoodplanner.data

object DefaultRecipes {
    val items = listOf(
        // --- BOWLS ---
        Recipe(name="Chicken-Basmati-Bowl", category="fit", kcal=520, protein=42.0, carbs=65.0, fat=8.0, ingredients="150g Hähnchen, 80g Reis, Brokkoli, Mais, Joghurt-Dressing", instructions="1. Den Reis in einem Sieb kalt abspülen und nach Packungsanweisung in 200ml Salzwasser mit 1 Prise Salz 10-12 Minuten gar kochen. 2. Das Hähnchen waschen, trocken tupfen und in mundgerechte Würfel schneiden. Mit Salz, Pfeffer und 1 TL Paprikapulver würzen. 3. 1 EL Olivenöl in einer beschichteten Pfanne erhitzen und das Hähnchen bei mittlerer Hitze 6-8 Minuten rundum goldbraun braten. 4. Den Brokkoli waschen, in Röschen teilen und 4-5 Minuten in kochendem Salzwasser blanchieren, dann kalt abschrecken. 5. 2 EL Joghurt mit 1 TL Zitronensaft, Salz und Pfeffer verrühren. 6. Alles in einer Schüssel anrichten und mit dem Dressing beträufeln."),
        Recipe(name="Tofu-Quinoa-Bowl", category="fit", kcal=480, protein=28.0, carbs=60.0, fat=12.0, ingredients="120g Tofu, 80g Quinoa, Gurke, Paprika, Tahini-Sauce", instructions="1. Die Quinoa in einem Sieb abspülen, dann mit 160ml Wasser und 1 Prise Salz aufkochen und bei niedriger Hitze 15 Minuten quellen lassen. 2. Den Tofu abtupfen und in 1cm Würfel schneiden. 3. 1 EL Sesamöl in einer Pfanne erhitzen und den Tofu darin bei hoher Hitze 6-8 Minuten kross braten, mit 1 EL Sojasauce ablöschen. 4. Die Gurke waschen und in dünne Scheiben schneiden, die Paprika entkernen und würfeln. 5. 2 EL Tahini mit 2 EL Zitronensaft, 1 Knoblauchzehe und 3 EL Wasser zu einer cremigen Sauce verrühren. 6. Quinoa in eine Schale geben, Tofu und Gemüse darauf anrichten und mit Tahini-Sauce beträufeln."),
        Recipe(name="Rinder-Reis-Bowl", category="build", kcal=650, protein=45.0, carbs=75.0, fat=15.0, ingredients="150g Rinderhüfte, 100g Reis, Bohnen, Zwiebeln", instructions="1. Den Reis nach Packungsanweisung in Salzwasser 12-15 Minuten gar kochen. 2. Das Rindersteak trocken tupfen, mit Salz und grobem Pfeffer würzen. 3. 1 EL Butterschmalz in einer Pfanne erhitzen und das Steak bei hoher Hitze 3-4 Minuten pro Seite scharf anbraten, dann 5 Minuten ruhen lassen. 4. Eine Zwiebel in Ringe schneiden und in derselben Pfanne 3 Minuten glasig braten. 5. Die Bohnen abgießen und in einem Topf erwärmen. 6. Das Steak in dünne Streifen schneiden, alles in einer Bowl anrichten."),
        Recipe(name="Lachs-Bulgur-Bowl", category="fit", kcal=580, protein=35.0, carbs=60.0, fat=20.0, ingredients="125g Lachs, 80g Bulgur, Spinat, Avocado", instructions="1. Den Bulgur mit 160ml kochendem Wasser übergießen, 1 Prise Salz zugeben und 10 Minuten zugedeckt quellen lassen. 2. Den Lachs waschen, trocken tupfen und mit Zitronensaft, Salz und Pfeffer würzen. 3. 1 EL Olivenöl in einer Pfanne erhitzen und den Lachs bei mittlerer Hitze 4 Minuten pro Seite braten. 4. Den Spinat waschen und 2 Minuten in der Pfanne zusammenfallen lassen. 5. Die Avocado halbieren, entkernen und in Scheiben schneiden. 6. Bulgur in eine Bowl geben, Spinat, Avocado und Lachs darauf anrichten."),
        Recipe(name="Asia-Garnele-Bowl", category="lose", kcal=390, protein=32.0, carbs=45.0, fat=6.0, ingredients="150g Garnelen, 60g Glasnudeln, Karotten", instructions="1. Die Glasnudeln in eine Schüssel geben und mit heißem Wasser übergießen, 5 Minuten einweichen lassen. 2. Die Garnelen waschen, schälen und den Darm entfernen. 3. 1 EL Sesamöl im Wok erhitzen, 1 Zehe Knoblauch und 1cm Ingwer fein hacken und kurz anbraten. 4. Die Garnelen im Wok bei starker Hitze 3-4 Minuten braten, mit 1 EL Sojasauce und 1 TL Limettensaft würzen. 5. Karotten schälen und in feine Streifen schneiden oder hobeln. 6. Glasnudeln abgießen, mit den Garnelen und Karotten anrichten."),
        Recipe(name="Falafel-Hummus-Bowl", category="fit", kcal=510, protein=18.0, carbs=62.0, fat=22.0, ingredients="6 Falafel, 2 EL Hummus, Couscous, Tomaten", instructions="1. Den Couscous mit 120ml kochendem Wasser übergießen, 1 Prise Salz und 1 TL Olivenöl zugeben, 5 Minuten quellen lassen und mit einer Gabel auflockern. 2. Die Falafel im Backofen bei 180°C Umluft 8-10 Minuten backen, bis sie knusprig sind. 3. Tomaten waschen und würfeln, eine Gurke in Scheiben schneiden. 4. Den Hummus in einer Schale glatt rühren. 5. Couscous in eine Bowl geben, Falafel, Gemüse und Hummus darauf anrichten und mit 1 EL Olivenöl beträufeln."),
        Recipe(name="Mexiko-Protein-Bowl", category="build", kcal=690, protein=40.0, carbs=80.0, fat=18.0, ingredients="Hähnchen, Reis, Mais, Bohnen, Avocado, Salsa", instructions="1. Den Reis in Salzwasser 12 Minuten gar kochen. 2. Das Hähnchen waschen, in Streifen schneiden, mit Salz, Pfeffer, 1 TL Kreuzkümmel und 1 TL Chili würzen. 3. 1 EL Öl in einer Pfanne erhitzen und das Hähnchen 6-8 Minuten scharf anbraten. 4. Mais und Bohnen abgießen und in einem Topf erwärmen. 5. Die Avocado halbieren, entkernen und in Scheiben schneiden. 6. Reis in eine Bowl geben, Hähnchen, Mais, Bohnen und Avocado darauf anrichten, mit 2 EL Salsa toppen."),
        Recipe(name="Skyr-Bowl: Beeren & Hanfsamen", category="lose", kcal=310, protein=38.0, carbs=25.0, fat=5.0, ingredients="300g Skyr, 150g Beeren, 1 EL Hanfsamen", instructions="1. Den Skyr in einer Schüssel glatt rühren. 2. Die Beeren waschen, TK-Beeren vorher antauen lassen. 3. 1 EL Hanfsamen in einer trockenen Pfanne 2 Minuten ohne Fett anrösten. 4. Den Skyr in eine Schale geben, Beeren darauf verteilen und mit den gerösteten Hanfsamen bestreuen. 5. Nach Wunsch mit 1 TL Honig oder Agavendicksaft süßen."),
        Recipe(name="Griechische Quinoa-Bowl", category="fit", kcal=460, protein=22.0, carbs=55.0, fat=14.0, ingredients="Quinoa, Feta-Light, Oliven, Gurke, Hähnchen", instructions="1. Die Quinoa abspülen und mit 160ml Wasser und 1 Prise Salz 15 Minuten quellen lassen. 2. Das Hähnchen waschen, in Streifen schneiden, mit Salz, Pfeffer und Oregano würzen. 3. 1 EL Olivenöl erhitzen und das Hähnchen 6 Minuten braten. 4. Die Gurke waschen und würfeln, Oliven in Scheiben schneiden, den Feta-Light zerbröseln. 5. Quinoa in eine Bowl geben, Hähnchen, Gurke, Oliven und Feta darauf verteilen. 6. Mit 1 EL Zitronensaft und 1 TL Olivenöl beträufeln."),
        Recipe(name="Sweet-Potato-Power-Bowl", category="build", kcal=620, protein=35.0, carbs=85.0, fat=10.0, ingredients="Süßkartoffel, Reis, Pute, Erbsen", instructions="1. Den Reis nach Packungsanweisung in Salzwasser 12 Minuten gar kochen. 2. Die Süßkartoffel schälen, in 2cm Würfel schneiden, mit 1 EL Olivenöl, Salz, Pfeffer und Rosmarin mischen und bei 200°C Umluft 20-25 Minuten backen. 3. Die Pute waschen, trocken tupfen und in Streifen schneiden. Mit Salz und Paprikapulver würzen. 4. 1 TL Öl in einer Pfanne erhitzen und die Pute 5-6 Minuten braten. 5. Die Erbsen in kochendem Wasser 3 Minuten garen. 6. Reis, Süßkartoffeln, Pute und Erbsen in einer Bowl anrichten."),

        // --- WRAPS ---
        Recipe(name="Fitness-Chicken-Wrap", category="fit", kcal=420, protein=35.0, carbs=40.0, fat=10.0, ingredients="Vollkornwrap, 120g Hähnchen, Salat, Skyr-Sauce", instructions="1. Das Hähnchen waschen, trocken tupfen und in dünne Streifen schneiden. Mit Salz, Pfeffer und 1 TL Paprikapulver würzen. 2. 1 TL Olivenöl in einer Pfanne erhitzen und das Hähnchen bei mittlerer Hitze 5-6 Minuten goldbraun braten. 3. 2 EL Skyr mit 1 TL Zitronensaft, Salz, Pfeffer und etwas Knoblauchpulver verrühren. 4. Den Vollkornwrap in einer trockenen Pfanne kurz von beiden Seiten erwärmen. 5. Den Wrap mit Salat belegen, Hähnchen darauf verteilen und mit Skyr-Sauce beträufeln. 6. Die Seiten einschlagen und fest aufrollen."),
        Recipe(name="Crunchy-Tofu-Wrap", category="fit", kcal=410, protein=25.0, carbs=45.0, fat=12.0, ingredients="Wrap, Räuchertofu, Rucola, Paprika, Hummus", instructions="1. Den Räuchertofu abtupfen und in dünne Scheiben schneiden. 2. 1 EL Sesamöl in einer Pfanne erhitzen und den Tofu 4-5 Minuten pro Seite knusprig braten. 3. Die Paprika entkernen und in feine Streifen schneiden. 4. Den Wrap erwärmen, großzügig mit 2 EL Hummus bestreichen. 5. Rucola waschen und trocken schütteln, auf dem Wrap verteilen. 6. Tofu und Paprika darauf legen, den Wrap fest einrollen und schräg halbieren."),
        Recipe(name="Beef-Salat-Wrap", category="build", kcal=550, protein=38.0, carbs=42.0, fat=18.0, ingredients="Wrap, 120g Rinderhack (mager), Eisberg", instructions="1. Das Rinderhack mit Salz, Pfeffer und 1 TL Senf würzen und gut durchkneten. 2. 1 TL Öl in einer Pfanne erhitzen und das Hack bei starker Hitze 5-6 Minuten krümelig braten. 3. Eisbergsalat in feine Streifen schneiden. 4. Den Wrap kurz erwärmen und mit 1 EL Joghurt bestreichen. 5. Salat und Hack auf dem Wrap verteilen, nach Wunsch Tomatenwürfel zugeben. 6. Eng einrollen, in der Pfanne von beiden Seiten je 1 Minute knusprig anbraten."),
        Recipe(name="Thunfisch-Protein-Wrap", category="lose", kcal=380, protein=32.0, carbs=35.0, fat=12.0, ingredients="Wrap, Dose Thunfisch, Ei, Gurke", instructions="1. Das Ei hart kochen (8 Minuten), abschrecken und in Scheiben schneiden. 2. Die Dose Thunfisch abgießen und mit einer Gabel zerkleinern. 3. Die Gurke waschen und in dünne Streifen schneiden. 4. Den Thunfisch mit 1 EL Magerquark und 1 TL Zitronensaft verrühren, mit Salz und Pfeffer abschmecken. 5. Den Wrap erwärmen, mit der Thunfischcreme bestreichen, Eierscheiben und Gurkenstreifen darauf legen. 6. Fest aufrollen und halbieren."),
        Recipe(name="Caesar-Chicken-Wrap", category="build", kcal=590, protein=42.0, carbs=45.0, fat=24.0, ingredients="Hähnchen, Parmesan, Romana, Wrap, Dressing", instructions="1. Das Hähnchen waschen, trocken tupfen und mit Salz, Pfeffer und 1 TL Knoblauchpulver würzen. 2. 1 TL Olivenöl in einer Pfanne erhitzen und das Hähnchen 6 Minuten pro Seite braten, dann in Streifen schneiden. 3. Romanasalat waschen und in Stücke zupfen. 2 EL Parmesan fein reiben. 4. Für das Dressing 2 EL Joghurt mit 1 TL Zitronensaft, 1 TL Öl, Salz, Pfeffer und 1 TL Parmesan verrühren. 5. Den Wrap erwärmen, mit Salat, Hähnchen und Parmesan belegen, Dressing darüber geben. 6. Einrollen und in der Pfanne kurz antoasten."),
        Recipe(name="Lachs-Spinat-Wrap", category="fit", kcal=470, protein=30.0, carbs=38.0, fat=22.0, ingredients="Räucherlachs, Frischkäse-Light, Spinat, Wrap", instructions="1. 2 EL Frischkäse-Light mit 1 TL Zitronensaft, Salz und Pfeffer glatt rühren. 2. Den Spinat waschen und trocken schleudern. 3. Den Wrap erwärmen und mit der Frischkäse-Creme bestreichen. 4. Den Räucherlachs in Streifen zupfen und auf dem Wrap verteilen. 5. Spinat darauf legen, nach Wunsch mit Zitronenabrieb bestreuen. 6. Den Wrap eng aufrollen, in zwei Hälften schneiden und kalt genießen."),
        Recipe(name="Hummus-Gemüse-Wrap", category="lose", kcal=340, protein=12.0, carbs=48.0, fat=14.0, ingredients="Hummus, bunte Paprika, Zucchini, Wrap", instructions="1. Die Paprika entkernen und in Streifen schneiden, die Zucchini waschen und längs in dünne Scheiben hobeln. 2. 1 TL Olivenöl in einer Pfanne erhitzen und das Gemüse 4 Minuten anbraten, mit Salz und Pfeffer würzen. 3. Den Wrap erwärmen und mit 3 EL Hummus bestreichen. 4. Das gebratene Gemüse darauf verteilen. 5. Nach Wunsch Rucola oder Sprossen zugeben. 6. Fest einrollen, halbieren und servieren."),
        Recipe(name="Puten-Curry-Wrap", category="fit", kcal=430, protein=35.0, carbs=42.0, fat=10.0, ingredients="Pute, Ananas, Curry-Skyr, Wrap", instructions="1. Die Pute waschen, trocken tupfen und in dünne Streifen schneiden. 2. 1 TL Öl in einer Pfanne erhitzen und die Pute mit 1 TL Currypulver 5-6 Minuten braten, mit Salz würzen. 3. 2 Scheiben Ananas aus der Dose abtropfen lassen und in kleine Stücke schneiden. 4. 2 EL Skyr mit 1 TL Currypulver und 1 TL Zitronensaft verrühren. 5. Den Wrap erwärmen, mit Curry-Skyr bestreichen, Pute und Ananas darauf geben. 6. Einrollen und in der Pfanne kurz von beiden Seiten anbraten."),
        Recipe(name="Ei-Bacon-Frühstückswrap", category="build", kcal=520, protein=32.0, carbs=35.0, fat=28.0, ingredients="2 Eier, Putenbacon, Käse, Wrap", instructions="1. Den Putenbacon in einer Pfanne ohne Fett 3-4 Minuten knusprig braten, herausnehmen. 2. 2 Eier mit 2 EL Milch, Salz und Pfeffer verquirlen. 3. 1 TL Butter in derselben Pfanne erhitzen und die Eier bei niedriger Hitze unter Rühren 3-4 Minuten zu Rührei stocken lassen. 4. Den Wrap erwärmen, 1 Scheibe Käse darauf legen. 5. Rührei und Bacon auf dem Wrap verteilen. 6. Fest einrollen, halbieren und sofort servieren."),
        Recipe(name="Falafel-Tahini-Wrap", category="fit", kcal=490, protein=16.0, carbs=55.0, fat=20.0, ingredients="Falafel, Tahini, Rotkohl, Wrap", instructions="1. 6 Falafel im Backofen bei 180°C Umluft 8-10 Minuten backen. 2. Den Rotkohl in feine Streifen hobeln, mit 1 EL Zitronensaft und einer Prise Salz durchkneten. 3. 2 EL Tahini mit 2 EL Wasser, 1 TL Zitronensaft und 1 Zehe Knoblauch zu einer Sauce verrühren. 4. Den Wrap erwärmen, mit Tahini-Sauce bestreichen. 5. Rotkohl und Falafel darauf verteilen, nach Wunsch etwas Petersilie zugeben. 6. Fest einrollen, halbieren und servieren."),

        // --- FRÜHSTÜCK ---
        Recipe(name="Power-Oats-Banane", category="fit", kcal=450, protein=20.0, carbs=70.0, fat=8.0, ingredients="Haferflocken, Milch, Banane, Honig", instructions="1. 50g Haferflocken mit 200ml Milch in einem kleinen Topf verrühren. 2. Unter Rühren bei mittlerer Hitze aufkochen und 3-4 Minuten köcheln lassen, bis ein cremiger Porridge entsteht. 3. Die Banane schälen und in Scheiben schneiden. 4. Den Porridge in eine Schale geben, Bananenscheiben darauf anrichten. 5. Mit 1 TL Honig beträufeln und nach Wunsch mit Zimt bestreuen."),
        Recipe(name="Skyr-Beeren-Traum", category="lose", kcal=280, protein=35.0, carbs=25.0, fat=2.0, ingredients="300g Skyr, Beeren, Mandeln", instructions="1. 300g Skyr in einer Schüssel glatt rühren. 2. 150g Beeren waschen, TK-Beeren kurz antauen lassen. 3. 10g Mandeln grob hacken. 4. Die Beeren unter den Skyr heben oder darauf anrichten. 5. Mit den gehackten Mandeln bestreuen und nach Wunsch mit 1 TL Honig süßen."),
        Recipe(name="Omelette-Spinat-Feta", category="fit", kcal=390, protein=28.0, carbs=5.0, fat=25.0, ingredients="3 Eier, Spinat, 30g Feta", instructions="1. 3 Eier mit Salz, Pfeffer und 1 EL Wasser verquirlen. 2. 50g frischen Spinat waschen, in einer Pfanne mit 1 TL Olivenöl 2 Minuten zusammenfallen lassen, herausnehmen. 3. 1 TL Olivenöl in einer beschichteten Pfanne erhitzen, die Eier hineingießen und bei mittlerer Hitze stocken lassen. 4. Den Spinat auf der noch flüssigen Oberseite verteilen, 30g Feta darüber bröseln. 5. Das Omelette vorsichtig zusammenklappen und 1-2 Minuten weitergaren. 6. Auf einen Teller gleiten lassen und servieren."),
        Recipe(name="Protein-Pancakes-Heidelbeer", category="build", kcal=520, protein=40.0, carbs=55.0, fat=12.0, ingredients="Hafermehl, Whey, Ei, Beeren", instructions="1. 40g Hafermehl, 30g Whey Vanille, 1 Ei und 60ml Milch zu einem glatten Teig verrühren. 2. 1 TL Backpulver und 1 Prise Salz zugeben. 3. 1 TL Kokosöl in einer Pfanne erhitzen, den Teig zu 4 kleinen Pancakes formen. 4. Jeden Pancake 2-3 Minuten pro Seite bei mittlerer Hitze backen. 5. 80g Heidelbeeren waschen und auf den Pancakes anrichten. 6. Nach Wunsch mit 1 EL Skyr oder Ahornsirup servieren."),
        Recipe(name="Hüttenkäse-Schnittlauch-Brot", category="lose", kcal=310, protein=25.0, carbs=35.0, fat=6.0, ingredients="Vollkornbrot, Hüttenkäse, Schnittlauch", instructions="1. 2 Scheiben Vollkornbrot toasten. 2. 150g Hüttenkäse in einer Schüssel mit einer Gabel etwas zerdrücken. 3. Den Schnittlauch waschen und in feine Röllchen schneiden. 4. Den Hüttenkäse mit Schnittlauch, Salz und Pfeffer verrühren. 5. Die Brotscheiben großzügig mit dem Hüttenkäse belegen. 6. Nach Wunsch mit Radieschenscheiben oder Gurkenscheiben toppen."),
        Recipe(name="Schoko-Protein-Porridge", category="build", kcal=480, protein=35.0, carbs=60.0, fat=10.0, ingredients="Haferflocken, Schoko-Whey, Wasser/Milch", instructions="1. 50g Haferflocken mit 200ml Milch in einem Topf verrühren. 2. Bei mittlerer Hitze unter Rühren 3-4 Minuten cremig kochen. 3. Vom Herd nehmen und 25g Schoko-Whey Proteinpulver einrühren, bis alles glatt ist. 4. 1 EL Kakaopulver unterrühren. 5. In eine Schale geben und nach Wunsch mit Bananenscheiben, Nüssen oder 1 TL Erdnussmus toppen."),
        Recipe(name="Rührei mit Lachs", category="fit", kcal=360, protein=32.0, carbs=2.0, fat=24.0, ingredients="3 Eier, 50g Räucherlachs, Kräuter", instructions="1. 3 Eier mit 2 EL Milch, Salz und Pfeffer verquirlen. 2. 1 TL Butter in einer beschichteten Pfanne bei niedriger Hitze schmelzen. 3. Die Eier hineingießen und langsam unter Rühren stocken lassen, 4-5 Minuten. 4. 50g Räucherlachs in Streifen zupfen. 5. Das Rührei auf einem Teller anrichten, Lachs darauf verteilen. 6. Mit frischen Kräutern (Dill, Petersilie) bestreuen und servieren."),
        Recipe(name="Banane-Erdnuss-Toast", category="fit", kcal=410, protein=15.0, carbs=55.0, fat=15.0, ingredients="2 Scheiben Vollkornbrot, Erdnussmus, Banane", instructions="1. 2 Scheiben Vollkornbrot toasten. 2. Jede Scheibe mit 1 EL Erdnussmus bestreichen. 3. Die Banane schälen und in dünne Scheiben schneiden. 4. Die Bananenscheiben auf dem Erdnussmus anrichten. 5. Nach Wunsch mit 1 TL Honig beträufeln, einer Prise Zimt bestreuen oder mit Chiasamen toppen."),
        Recipe(name="Chia-Pudding Vanille", category="lose", kcal=290, protein=12.0, carbs=20.0, fat=18.0, ingredients="Chiasamen, Mandelmilch, Vanille, Obst", instructions="1. 3 EL Chiasamen mit 200ml Mandelmilch in einem Glas verrühren. 2. 1 TL Vanilleextrakt und 1 TL Honig oder Agavendicksaft zugeben. 3. Gut umrühren, damit keine Klumpen entstehen. 4. Das Glas abdecken und über Nacht (mindestens 6 Stunden) in den Kühlschrank stellen. 5. Vor dem Servieren umrühren und mit frischem Obst (Beeren, Mango) toppen."),
        Recipe(name="Frühstücks-Quark-Müsli", category="fit", kcal=440, protein=30.0, carbs=50.0, fat=12.0, ingredients="Quark, Haferflocken, Apfel, Nüsse", instructions="1. 200g Magerquark in eine Schüssel geben und glatt rühren. 2. 40g Haferflocken und 100ml Milch unterrühren, 5 Minuten quellen lassen. 3. Den Apfel waschen, entkernen und in kleine Würfel schneiden. 4. 15g Nüsse (Mandeln oder Walnüsse) grob hacken. 5. Alles mit dem Quark vermischen, mit 1 TL Honig süßen. 6. Nach Wunsch mit Zimt bestreuen und servieren."),

        // --- SMOOTHIES ---
        Recipe(name="Grüner Protein-Smoothie", category="lose", kcal=250, protein=25.0, carbs=20.0, fat=3.0, ingredients="Spinat, Whey Vanille, Apfel, Wasser", instructions="1. Eine Handvoll frischen Spinat waschen. 2. Den Apfel waschen, entkernen und in Stücke schneiden. 3. Alle Zutaten mit 25g Whey Vanille und 250ml kaltem Wasser in den Standmixer geben. 4. 45 Sekunden auf höchster Stufe mixen bis alles cremig ist. 5. In ein Glas gießen und sofort genießen."),
        Recipe(name="Beeren-Shake-Oats", category="fit", kcal=380, protein=30.0, carbs=45.0, fat=5.0, ingredients="Beeren, Haferflocken, Whey, Milch", instructions="1. 80g TK-Beeren abwiegen und kurz antauen lassen. 2. 30g Haferflocken, 30g Whey Protein (Vanille), 200ml Milch und die Beeren in den Mixer geben. 3. 1 TL Honig oder Agavendicksaft zugeben. 4. 60 Sekunden cremig mixen. 5. In ein großes Glas gießen und als Mahlzeit-Ersatz genießen."),
        Recipe(name="Schoko-Bananen-Booster", category="build", kcal=490, protein=35.0, carbs=65.0, fat=10.0, ingredients="Banane, Whey Schoko, Erdnussmus", instructions="1. Eine große Banane schälen und in Stücke brechen, 20g in den Gefrierschrank legen. 2. 35g Whey Schoko, 1 EL Erdnussmus und 250ml Milch in den Mixer geben. 3. Die gefrorenen Bananenstücke zugeben. 4. 60 Sekunden auf höchster Stufe mixen. 5. In ein Glas gießen, nach Wunsch mit 1 TL Kakaonibs bestreuen."),
        Recipe(name="Mango-Lassi-Protein", category="fit", kcal=320, protein=28.0, carbs=40.0, fat=4.0, ingredients="Mango, Joghurt-Light, Whey, Eis", instructions="1. 150g Mango (frisch oder TK) in Stücke schneiden. 2. 100g Joghurt-Light, 25g Whey Vanille, 100ml Milch und 3 Eiswürfel zugeben. 3. 1 TL Zitronensaft und 1 Prise Kardamom zugeben. 4. 45 Sekunden cremig mixen. 5. In ein Glas gießen und mit einer Prise Kardamom bestreuen."),
        Recipe(name="Erdbeer-Quark-Smoothie", category="lose", kcal=270, protein=32.0, carbs=28.0, fat=2.0, ingredients="Erdbeeren, Magerquark, Spritzer Zitrone", instructions="1. 150g Erdbeeren waschen, putzen und in Stücke schneiden. 2. 150g Magerquark, 100ml Wasser und die Erdbeeren in den Mixer geben. 3. 1 Spritzer Zitronensaft und 1 TL Honig zugeben. 4. 30 Sekunden mixen. 5. In ein Glas füllen und mit einer Erdbeere garnieren."),
        Recipe(name="Kaffee-Whey-Eis-Shake", category="fit", kcal=180, protein=26.0, carbs=10.0, fat=2.0, ingredients="Espresso, Whey, Eiswürfel, etwas Milch", instructions="1. Einen doppelten Espresso (60ml) kochen und abkühlen lassen. 2. 25g Whey Vanille, 100ml Milch, 5 Eiswürfel und den abgekühlten Espresso in den Mixer geben. 3. 30 Sekunden schaumig mixen. 4. In ein Glas gießen. 5. Nach Wunsch mit Kakaopulver bestreuen und sofort servieren."),
        Recipe(name="Tropischer Ananas-Shake", category="lose", kcal=240, protein=24.0, carbs=30.0, fat=1.0, ingredients="Ananas, Whey, Kokoswasser", instructions="1. 150g frische Ananas schälen, den Strunk entfernen und in Stücke schneiden. 2. 25g Whey Vanille, 200ml Kokoswasser und die Ananas in den Mixer geben. 3. 1 TL Limettensaft zugeben. 4. 45 Sekunden mixen. 5. In ein Glas gießen, nach Wunsch mit etwas Kokosraspel bestreuen und sofort trinken."),
        Recipe(name="Power-Greens-Zitrone", category="lose", kcal=150, protein=10.0, carbs=20.0, fat=1.0, ingredients="Gurke, Apfel, Zitrone, Spinat, Ingwer", instructions="1. Eine halbe Gurke waschen und in Stücke schneiden. 2. Einen Apfel waschen, entkernen und würfeln. 3. Eine Handvoll Spinat, den Saft einer halben Zitrone und 1cm Ingwer geschält zugeben. 4. 200ml kaltes Wasser zugeben und 60 Sekunden mixen. 5. 20g Whey neutral einrühren, in ein Glas gießen und sofort genießen."),
        Recipe(name="Bulk-Mass-Shake", category="build", kcal=850, protein=50.0, carbs=100.0, fat=30.0, ingredients="Haferflocken, Erdnussmus, Whey, Banane, Milch", instructions="1. 60g Haferflocken, 40g Whey, 2 EL Erdnussmus, eine Banane und 400ml Milch in den Mixer geben. 2. 1 EL Honig zugeben. 3. 60-90 Sekunden auf höchster Stufe cremig mixen. 4. In einen großen Shake-Behälter füllen. 5. Nach dem Training oder als kräftige Mahlzeit genießen."),
        Recipe(name="Waldfrucht-Regenerations-Shake", category="fit", kcal=340, protein=30.0, carbs=45.0, fat=3.0, ingredients="TK-Waldfrüchte, Whey, Dextrose", instructions="1. 100g TK-Waldfrüchte abwiegen. 2. 30g Whey Protein, 20g Dextrose und 300ml Wasser zugeben. 3. 1 TL Leinöl für gesunde Fette zugeben (optional). 4. 60 Sekunden cremig mixen. 5. Direkt nach dem Training trinken für optimale Regeneration."),

        // --- SALATE ---
        Recipe(name="Athleten-Thunfisch-Salat", category="lose", kcal=320, protein=45.0, carbs=10.0, fat=8.0, ingredients="Thunfisch, Eier, Salat, Essig/Öl", instructions="1. 2 Eier hart kochen (8 Minuten), abschrecken und vierteln. 2. Die Dose Thunfisch abgießen und mit einer Gabel zerpflücken. 3. 200g gemischten Salat waschen und trocken schleudern. 4. 2 EL Essig mit 1 EL Olivenöl, Salz und Pfeffer zu einem Dressing verrühren. 5. Salat auf einem Teller anrichten, Thunfisch und Eier darauf verteilen. 6. Mit dem Dressing beträufeln und servieren."),
        Recipe(name="Hähnchen-Paprika-Salat", category="fit", kcal=350, protein=38.0, carbs=15.0, fat=12.0, ingredients="Hähnchen, Paprika, Rucola", instructions="1. 120g Hähnchenbrust waschen, trocken tupfen, mit Salz und Pfeffer würzen. 2. 1 TL Olivenöl in einer Pfanne erhitzen und das Hähnchen 6 Minuten pro Seite braten, dann in Streifen schneiden. 3. Eine rote Paprika entkernen und in Streifen schneiden. 4. 80g Rucola waschen und trocken schleudern. 5. 2 EL Balsamico-Essig mit 1 EL Olivenöl verrühren. 6. Alles in einer Schüssel vermengen und mit dem Dressing servieren."),
        Recipe(name="Kichererbsen-Feta-Salat", category="fit", kcal=440, protein=22.0, carbs=45.0, fat=18.0, ingredients="Kichererbsen, Feta, Gurke, Tomate", instructions="1. Die Dose Kichererbsen abgießen und abspülen. 2. Eine Gurke waschen, halbieren und in Scheiben schneiden. 3. 3 Tomaten waschen und würfeln. 4. 80g Feta in Würfel schneiden oder zerbröseln. 5. 2 EL Olivenöl mit 1 EL Zitronensaft, Salz, Pfeffer und 1 TL Oregano verrühren. 6. Alles in einer großen Schüssel vermengen, Dressing darübergießen und vorsichtig unterheben."),
        Recipe(name="Linsensalat mediterran", category="fit", kcal=390, protein=25.0, carbs=40.0, fat=12.0, ingredients="Linsen, Tomaten, Petersilie, Zitrone", instructions="1. 150g braune Linsen in reichlich Wasser 20-25 Minuten bissfest kochen, abgießen und abkühlen lassen. 2. 3 Tomaten würfeln, eine kleine Zwiebel fein hacken. 3. Eine Handvoll Petersilie waschen und hacken. 4. 3 EL Olivenöl mit dem Saft einer Zitrone, Salz, Pfeffer und 1 TL Kreuzkümmel verrühren. 5. Linsen, Tomaten, Zwiebel und Petersilie vermengen. 6. Das Dressing darübergießen und mindestens 30 Minuten durchziehen lassen."),
        Recipe(name="Rindersteak-Streifen auf Salat", category="build", kcal=510, protein=48.0, carbs=12.0, fat=28.0, ingredients="Steak, gemischter Salat, Balsamico", instructions="1. Das Rindersteak (150g) trocken tupfen, mit Salz und grobem Pfeffer würzen. 2. 1 EL Butterschmalz in einer Grillpfanne erhitzen und das Steak 3-4 Minuten pro Seite scharf anbraten, 5 Minuten ruhen lassen. 3. 200g gemischten Salat waschen und trocken schleudern. 4. 2 EL Balsamico-Creme mit 1 EL Olivenöl verrühren. 5. Das Steak in dünne Streifen schneiden. 6. Salat auf einem Teller anrichten, Steak-Streifen darauf legen und mit Balsamico-Dressing beträufeln."),
        Recipe(name="Couscous-Minz-Salat", category="lose", kcal=310, protein=12.0, carbs=55.0, fat=6.0, ingredients="Couscous, Minze, Gurke, Tomate", instructions="1. 80g Couscous mit 120ml kochendem Wasser übergießen, 1 Prise Salz zugeben und 5 Minuten quellen lassen, mit einer Gabel auflockern. 2. Eine Gurke waschen und würfeln. 3. 2 Tomaten würfeln. 4. Eine Handvoll frische Minze waschen und fein hacken. 5. 2 EL Zitronensaft mit 1 EL Olivenöl, Salz und Pfeffer verrühren. 6. Couscous, Gemüse und Minze vermengen, Dressing darübergießen und gut durchmischen."),
        Recipe(name="Quinoa-Brokkoli-Salat", category="fit", kcal=420, protein=20.0, carbs=50.0, fat=15.0, ingredients="Quinoa, gedämpfter Brokkoli, Nüsse", instructions="1. 80g Quinoa abspülen, mit 160ml Wasser und 1 Prise Salz 15 Minuten quellen lassen. 2. 200g Brokkoli in Röschen teilen und 4-5 Minuten in kochendem Salzwasser blanchieren, kalt abschrecken. 3. 20g Walnüsse grob hacken und in einer trockenen Pfanne 2-3 Minuten rösten. 4. 2 EL Olivenöl mit 1 EL Zitronensaft, Salz und Pfeffer verrühren. 5. Quinoa, Brokkoli und Nüsse vermengen. 6. Das Dressing darübergießen und lauwarm oder kalt servieren."),
        Recipe(name="Eier-Salat (light)", category="lose", kcal=280, protein=24.0, carbs=8.0, fat=18.0, ingredients="3 Eier, Joghurt-Dressing, Kräuter", instructions="1. 3 Eier hart kochen (8-9 Minuten), abschrecken, pellen und grob hacken. 2. 2 EL Joghurt mit 1 TL Senf, 1 TL Zitronensaft, Salz und Pfeffer verrühren. 3. Eine Handvoll frische Kräuter (Schnittlauch, Petersilie, Dill) waschen und hacken. 4. Die Eier mit dem Dressing vermengen. 5. Die Kräuter unterheben. 6. Auf Vollkornbrot oder als Beilage zu grünem Salat servieren."),
        Recipe(name="Garnelen-Avocado-Salat", category="fit", kcal=450, protein=30.0, carbs=15.0, fat=30.0, ingredients="Garnelen, Avocado, Blattsalat, Limette", instructions="1. 150g Garnelen waschen, schälen und den Darm entfernen. 2. 1 TL Olivenöl in einer Pfanne erhitzen und die Garnelen 3-4 Minuten braten, mit Salz und Pfeffer würzen. 3. 100g Blattsalat waschen und trocken schleudern. 4. Eine Avocado halbieren, entkernen, schälen und in Scheiben schneiden. 5. Den Saft einer Limette mit 1 EL Olivenöl, Salz und Pfeffer verrühren. 6. Salat, Avocado und Garnelen auf einem Teller anrichten, mit dem Dressing beträufeln."),
        Recipe(name="Hüttenkäse-Rohkost-Salat", category="lose", kcal=220, protein=26.0, carbs=15.0, fat=5.0, ingredients="Hüttenkäse, Karotten, Gurke, Paprika", instructions="1. 200g Hüttenkäse in eine Schüssel geben. 2. Eine Karotte schälen und grob raspeln. 3. Eine halbe Gurke waschen und würfeln. 4. Eine halbe Paprika entkernen und in kleine Würfel schneiden. 5. Das gesamte Gemüse zum Hüttenkäse geben, mit Salz, Pfeffer und 1 TL Zitronensaft würzen. 6. Gut vermischen, nach Wunsch mit frischen Kräutern bestreuen und servieren."),

        // --- WARM / ABENDESSEN ---
        Recipe(name="Puten-Süßkartoffel-Pfanne", category="fit", kcal=510, protein=40.0, carbs=55.0, fat=10.0, ingredients="Pute, Süßkartoffel, Zucchini", instructions="1. 200g Putenbrust in Streifen schneiden, mit Salz, Pfeffer und 1 TL Paprikapulver würzen. 2. Eine Süßkartoffel schälen und in 1cm Würfel schneiden. 3. 1 EL Olivenöl in einer Pfanne erhitzen und die Süßkartoffelwürfel 8-10 Minuten bei mittlerer Hitze braten. 4. Die Pute zugeben und weitere 5 Minuten mitbraten. 5. Eine Zucchini waschen, in Scheiben schneiden und 3 Minuten mitbraten. 6. Mit Salz, Pfeffer und frischen Kräutern abschmecken und servieren."),
        Recipe(name="Pasta-Thunfisch-Tomate", category="build", kcal=620, protein=42.0, carbs=80.0, fat=12.0, ingredients="Pasta, Thunfisch, Tomatensauce", instructions="1. 100g Vollkornpasta in Salzwasser nach Packungsanweisung bissfest kochen. 2. Eine Zwiebel fein hacken und in 1 TL Olivenöl glasig dünsten. 3. 400g passierte Tomaten zugeben, mit Salz, Pfeffer und 1 TL Oregano würzen und 10 Minuten köcheln lassen. 4. Die Dose Thunfisch abgießen und in die Sauce bröseln, 2 Minuten erwärmen. 5. Die Pasta abgießen und zur Sauce geben. 6. Alles gut vermengen und mit Parmesan servieren."),
        Recipe(name="Chili sin Carne (Linsen)", category="fit", kcal=450, protein=28.0, carbs=65.0, fat=5.0, ingredients="Linsen, Bohnen, Mais, Tomatenmark", instructions="1. 150g rote Linsen abspülen. 2. Eine Zwiebel und 2 Knoblauchzehen fein hacken, in 1 EL Öl glasig dünsten. 3. 2 EL Tomatenmark zugeben und kurz mitrösten. 4. 400ml Gemüsebrühe, die Linsen, eine Dose Kidneybohnen und eine Dose Mais zugeben. 5. Mit Chili, Kreuzkümmel, Salz und Pfeffer würzen und 20 Minuten köcheln lassen. 6. Mit frischem Koriander bestreuen und servieren."),
        Recipe(name="Steak mit Kartoffelspalten", category="build", kcal=680, protein=50.0, carbs=45.0, fat=30.0, ingredients="Steak, Kartoffeln, Spargel", instructions="1. 300g Kartoffeln gründlich waschen und in Spalten schneiden. 2. Die Kartoffelspalten mit 1 EL Olivenöl, Salz, Pfeffer und Rosmarin mischen und bei 200°C Umluft 25-30 Minuten backen. 3. Das Steak trocken tupfen, mit Salz und Pfeffer würzen. 4. 1 EL Butterschmalz in einer Grillpfanne erhitzen und das Steak 3-4 Minuten pro Seite scharf braten, 5 Minuten ruhen lassen. 5. Den grünen Spargel waschen, holzige Enden entfernen und 5 Minuten in der Pfanne mitbraten. 6. Das Steak aufschneiden und mit Kartoffelspalten und Spargel servieren."),
        Recipe(name="Dorschfilet auf Blattspinat", category="lose", kcal=340, protein=42.0, carbs=8.0, fat=12.0, ingredients="Dorsch, Spinat, Zitrone", instructions="1. 200g Dorschfilet waschen, trocken tupfen und mit Zitronensaft, Salz und Pfeffer würzen. 2. 200g frischen Spinat waschen. 3. 1 TL Olivenöl in einer Pfanne erhitzen und den Spinat 2-3 Minuten zusammenfallen lassen, mit einer Prise Muskat würzen. 4. Das Dorschfilet in derselben Pfanne 4 Minuten pro Seite bei mittlerer Hitze braten. 5. Den Spinat auf einem Teller anrichten, den Fisch darauf setzen. 6. Mit Zitronenscheiben garnieren und servieren."),
        Recipe(name="Hähnchen-Curry (Indisch)", category="fit", kcal=540, protein=40.0, carbs=60.0, fat=15.0, ingredients="Hähnchen, Reis, Kokosmilch-Light, Gewürze", instructions="1. 80g Reis in Salzwasser kochen. 2. 200g Hähnchen in Würfel schneiden, mit Salz und Pfeffer würzen. 3. Eine Zwiebel, 2 Knoblauchzehen und 1cm Ingwer fein hacken, in 1 EL Öl glasig dünsten. 4. 2 TL Currypulver, 1 TL Kreuzkümmel und 1 TL Kurkuma zugeben und kurz mitrösten. 5. 200ml Kokosmilch-Light und 100ml Wasser zugeben, das Hähnchen einlegen und 15 Minuten köcheln lassen. 6. Mit Reis servieren und mit Koriander bestreuen."),
        Recipe(name="Gebratener Reis mit Tofu", category="fit", kcal=470, protein=25.0, carbs=70.0, fat=10.0, ingredients="Reis, Tofu, Erbsen, Sojasauce", instructions="1. 100g Reis nach Packungsanweisung kochen und abkühlen lassen (am besten vom Vortag). 2. 150g Tofu abtupfen, in kleine Würfel schneiden. 3. 1 EL Sesamöl im Wok erhitzen und den Tofu 5 Minuten kross braten, herausnehmen. 4. Eine Zwiebel und 2 Knoblauchzehen hacken, im Wok anbraten. 5. Den gekochten Reis und 50g Erbsen zugeben, unter Rühren 3-4 Minuten braten. 6. 2 EL Sojasauce, den Tofu zugeben, mit Frühlingszwiebeln bestreuen und servieren."),
        Recipe(name="Lachs aus dem Ofen", category="fit", kcal=580, protein=35.0, carbs=10.0, fat=40.0, ingredients="Lachs, Spargel, Kirschtomaten", instructions="1. Den Backofen auf 200°C Umluft vorheizen. 2. 200g Lachsfilet waschen, trocken tupfen, mit Salz, Pfeffer und Zitronensaft würzen. 3. 200g grünen Spargel waschen, holzige Enden entfernen. 4. 150g Kirschtomaten waschen und halbieren. 5. Lachs, Spargel und Tomaten auf ein mit Backpapier belegtes Blech legen, mit 2 EL Olivenöl beträufeln. 6. 18-20 Minuten backen, bis der Lachs gar und der Spargel bissfest ist."),
        Recipe(name="Rindergeschnetzeltes Pilze", category="build", kcal=710, protein=48.0, carbs=65.0, fat=25.0, ingredients="Rind, Pilze, Reis, Schmand-Light", instructions="1. 80g Reis in Salzwasser kochen. 2. 200g Rindfleisch in dünne Streifen schneiden, mit Salz und Pfeffer würzen. 3. 200g Champignons putzen und in Scheiben schneiden. 4. 1 EL Öl erhitzen, das Fleisch scharf anbraten und herausnehmen. 5. Die Pilze im Bratensatz 5 Minuten braten, 1 Zwiebel zugeben. 6. 100ml Brühe und 2 EL Schmand-Light zugeben, das Fleisch zurückgeben und 5 Minuten köcheln lassen, mit Reis servieren."),
        Recipe(name="Linsenbolognese Vollkorn", category="fit", kcal=490, protein=26.0, carbs=75.0, fat=8.0, ingredients="Linsen, Vollkornnudeln, Tomaten", instructions="1. 100g Vollkornnudeln in Salzwasser bissfest kochen. 2. 150g rote Linsen abspülen. 3. Eine Zwiebel und 2 Knoblauchzehen hacken, in 1 EL Öl glasig dünsten. 4. 400g passierte Tomaten, die Linsen, 1 TL Oregano, Salz und Pfeffer zugeben. 5. 20 Minuten köcheln lassen, bis die Linsen weich sind. 6. Nudeln abgießen, mit der Linsenbolognese vermengen und servieren."),
        Recipe(name="Kartoffeln & Kräuterquark", category="lose", kcal=320, protein=18.0, carbs=55.0, fat=4.0, ingredients="Kartoffeln, Quark, Schnittlauch", instructions="1. 400g Kartoffeln waschen und in Salzwasser 20 Minuten garen. 2. 200g Magerquark mit 2 EL Milch glatt rühren. 3. Eine Handvoll Schnittlauch waschen und in Röllchen schneiden. 4. Den Schnittlauch zum Quark geben, mit Salz, Pfeffer und 1 TL Zitronensaft würzen. 5. Die Kartoffeln abgießen und ausdampfen lassen. 6. Kartoffeln pellen, mit dem Kräuterquark servieren."),
        Recipe(name="Putenschnitzel (unpaniert)", category="lose", kcal=290, protein=45.0, carbs=5.0, fat=8.0, ingredients="Pute, grüner Salat, Zitrone", instructions="1. 200g Putenschnitzel waschen, trocken tupfen und dünn klopfen. 2. Mit Salz, Pfeffer und 1 TL Paprikapulver würzen. 3. 1 TL Olivenöl in einer beschichteten Pfanne erhitzen und die Schnitzel 4 Minuten pro Seite braten. 4. 150g grünen Salat waschen und trocken schleudern. 5. 2 EL Zitronensaft mit 1 EL Olivenöl, Salz und Pfeffer verrühren. 6. Salat auf einem Teller anrichten, Schnitzel dazu legen und mit Zitronenscheiben garnieren."),
        Recipe(name="Gnocchi mit Salbei-Pute", category="build", kcal=630, protein=38.0, carbs=70.0, fat=22.0, ingredients="Gnocchi, Putenstreifen, Salbei, Butter", instructions="1. 250g Gnocchi in Salzwasser 2-3 Minuten garen, bis sie an die Oberfläche steigen. 2. 150g Putenbrust in Streifen schneiden, mit Salz und Pfeffer würzen. 3. 1 EL Butter in einer Pfanne erhitzen und die Putenstreifen 5 Minuten braten, herausnehmen. 4. 6-8 frische Salbeiblätter in der Butter 1 Minute knusprig braten. 5. Die Gnocchi abgießen und in der Salbeibutter 3-4 Minuten goldbraun braten. 6. Die Pute zugeben, alles vermengen und mit Parmesan servieren."),
        Recipe(name="Zucchini-Nudeln Bolognese", category="lose", kcal=350, protein=35.0, carbs=15.0, fat=15.0, ingredients="Zucchini (Zoodles), Rinderhack, Tomate", instructions="1. 2 Zucchini waschen und mit einem Spiralschneider in Nudelform bringen. 2. 150g Rinderhack mit Salz und Pfeffer würzen. 3. 1 TL Öl erhitzen und das Hack 5 Minuten krümelig braten. 4. 200g passierte Tomaten, 1 TL Oregano zugeben und 10 Minuten köcheln lassen. 5. Die Zoodles in einer separaten Pfanne 2 Minuten ohne Fett erhitzen. 6. Bolognese über die Zoodles geben und servieren."),
        Recipe(name="One-Pot-Pasta (Chicken)", category="fit", kcal=560, protein=42.0, carbs=75.0, fat=12.0, ingredients="Nudeln, Hähnchen, Brokkoli, Brühe", instructions="1. 150g Hähnchenbrust in Würfel schneiden. 2. 100g Nudeln, 200g Brokkoliröschen, das Hähnchen und 400ml Gemüsebrühe in einen großen Topf geben. 3. Bei starker Hitze aufkochen, dann 12 Minuten bei mittlerer Hitze köcheln lassen, bis die Nudeln gar sind. 4. Gelegentlich umrühren, damit nichts anbrennt. 5. 2 EL Frischkäse-Light unterrühren, mit Salz, Pfeffer und Muskat abschmecken. 6. In tiefen Tellern servieren."),

        // --- REGENERATION ---
        Recipe(name="Regenerations-Bowl (Lachs)", category="fit", kcal=590, protein=38.0, carbs=50.0, fat=25.0, ingredients="Lachs, Wildreis, Avocado, Brokkoli", instructions="1. 80g Wildreis in Salzwasser 35-40 Minuten gar kochen. 2. Den Lachs waschen, trocken tupfen, mit Salz, Pfeffer und 1 EL Zitronensaft würzen. 3. 1 TL Öl in einer Pfanne erhitzen und den Lachs 4 Minuten pro Seite braten. 4. 150g Brokkoli in Röschen teilen und 4 Minuten blanchieren. 5. Eine halbe Avocado in Scheiben schneiden. 6. Wildreis in eine Bowl geben, Lachs, Brokkoli und Avocado darauf anrichten."),
        Recipe(name="Heidelbeer-Quark-Auflauf", category="fit", kcal=420, protein=45.0, carbs=40.0, fat=8.0, ingredients="Magerquark, Eier, Haferflocken, Beeren", instructions="1. Den Backofen auf 180°C Umluft vorheizen. 2. 300g Magerquark mit 2 Eiern, 40g Haferflocken und 1 EL Honig glatt rühren. 3. 150g Heidelbeeren waschen und vorsichtig unterheben. 4. Eine Auflaufform einfetten und die Masse einfüllen. 5. 30-35 Minuten backen, bis der Auflauf goldbraun und fest ist. 6. Lauwarm servieren, nach Wunsch mit Joghurt toppen."),
        Recipe(name="Warmer Linsensalat Protein", category="fit", kcal=410, protein=30.0, carbs=50.0, fat=10.0, ingredients="Linsen, Spinat, Ei, Walnüsse", instructions="1. 150g braune Linsen in Salzwasser 20 Minuten bissfest kochen. 2. 2 Eier hart kochen (8 Minuten), pellen und vierteln. 3. 100g frischen Spinat waschen. 4. 20g Walnüsse grob hacken und in einer trockenen Pfanne 2 Minuten rösten. 5. Die Linsen abgießen, mit 2 EL Essig, 1 EL Olivenöl, Salz und Pfeffer vermischen. 6. Spinat unterheben, mit Eiern und Walnüssen toppen und lauwarm servieren."),
        Recipe(name="Protein-Müsli (Extra)", category="fit", kcal=450, protein=35.0, carbs=55.0, fat=12.0, ingredients="Hafer, Whey, Nüsse, Beeren, Milch", instructions="1. 50g Haferflocken in eine Schüssel geben. 2. 30g Whey Protein Vanille dazu geben. 3. 20g gemischte Nüsse (Mandeln, Walnüsse) grob hacken. 4. 80g frische Beeren waschen. 5. Alles mit 200ml Milch übergießen. 6. Nach Wunsch mit 1 TL Honig süßen und sofort genießen."),
        Recipe(name="Steak & Süßkartoffel", category="build", kcal=750, protein=55.0, carbs=60.0, fat=30.0, ingredients="Rinderfilet, Süßkartoffel, Bohnen", instructions="1. Eine Süßkartoffel schälen und in Spalten schneiden. Mit 1 EL Olivenöl, Salz und Rosmarin mischen, bei 200°C 25 Minuten backen. 2. 200g Rinderfilet trocken tupfen, mit Salz und Pfeffer würzen. 3. 1 EL Butterschmalz in einer Pfanne erhitzen und das Filet 3-4 Minuten pro Seite scharf braten, 5 Minuten ruhen lassen. 4. 150g grüne Bohnen in Salzwasser 6 Minuten blanchieren. 5. Das Steak in Scheiben schneiden. 6. Mit Süßkartoffelspalten und Bohnen servieren."),
        
        // --- ADDING MORE TO REACH +60 NEW ONES ---
        Recipe(name="Bowl: Garnelen & Mango", category="fit", kcal=430, protein=35.0, carbs=55.0, fat=8.0, ingredients="Garnelen, Reis, Mango, Edamame", instructions="1. 80g Reis nach Packungsanweisung kochen. 2. 150g Garnelen waschen und schälen. 3. 1 TL Öl im Wok erhitzen und die Garnelen 3 Minuten braten, mit Salz und Chili würzen. 4. Eine halbe Mango schälen und in Würfel schneiden. 5. 50g Edamame in kochendem Wasser 3 Minuten garen. 6. Reis in eine Bowl geben, Garnelen, Mango und Edamame darauf anrichten."),
        Recipe(name="Wrap: Pute & Hummus", category="fit", kcal=460, protein=32.0, carbs=45.0, fat=15.0, ingredients="Wrap, Pute, Hummus, Salat", instructions="1. 120g Putenbrust in Streifen schneiden, mit Salz und Pfeffer würzen. 2. 1 TL Öl in einer Pfanne erhitzen und die Pute 5 Minuten braten. 3. Den Wrap erwärmen und mit 2 EL Hummus bestreichen. 4. Salat waschen, auf dem Wrap verteilen. 5. Die Pute darauf geben. 6. Fest einrollen, halbieren und servieren."),
        Recipe(name="Omelette: Pilze & Zwiebel", category="lose", kcal=310, protein=24.0, carbs=8.0, fat=20.0, ingredients="3 Eier, Champignons, Zwiebel", instructions="1. 100g Champignons putzen und in Scheiben schneiden. Eine Zwiebel in Ringe schneiden. 2. 1 TL Öl in einer Pfanne erhitzen und Pilze und Zwiebel 5 Minuten braten, herausnehmen. 3. 3 Eier mit Salz, Pfeffer und 1 EL Wasser verquirlen. 4. 1 TL Butter in der Pfanne erhitzen, die Eier hineingießen und bei niedriger Hitze stocken lassen. 5. Die Pilz-Zwiebel-Mischung auf der noch flüssigen Seite verteilen. 6. Das Omelette zusammenklappen und servieren."),
        Recipe(name="Skyr mit Leinsamen", category="lose", kcal=260, protein=32.0, carbs=12.0, fat=8.0, ingredients="Skyr, Leinsamen, Beeren", instructions="1. 250g Skyr in eine Schüssel geben. 2. 1 EL Leinsamen in einer trockenen Pfanne kurz anrösten. 3. 100g Beeren waschen. 4. Die Beeren unter den Skyr heben. 5. Mit den gerösteten Leinsamen bestreuen. 6. Nach Wunsch mit 1 TL Honig süßen."),
        Recipe(name="Salat: Pute & Ananas", category="lose", kcal=310, protein=35.0, carbs=25.0, fat=6.0, ingredients="Salat, Pute, Ananas", instructions="1. 120g Putenbrust waschen, trocken tupfen und in Streifen schneiden. 2. 1 TL Öl erhitzen und die Pute 5-6 Minuten braten, mit Salz und Pfeffer würzen. 3. 150g gemischten Salat waschen und trocken schleudern. 4. 2 Scheiben Ananas in Stücke schneiden. 5. 2 EL Essig mit 1 EL Öl, Salz und Pfeffer verrühren. 6. Alles vermengen und mit dem Dressing servieren."),
        Recipe(name="Pasta Bolognese (mager)", category="build", kcal=680, protein=45.0, carbs=85.0, fat=15.0, ingredients="Pasta, Rinderhack, Tomaten", instructions="1. 120g Vollkornpasta in Salzwasser bissfest kochen. 2. 150g Rinderhack mit Salz und Pfeffer würzen. 3. 1 TL Öl erhitzen und das Hack 5 Minuten krümelig braten. 4. Eine Zwiebel hacken und mit 400g passierten Tomaten, 1 TL Oregano zugeben, 15 Minuten köcheln. 5. Nudeln abgießen. 6. Mit der Bolognese vermengen und mit Parmesan servieren."),
        Recipe(name="Kartoffel-Quark-Teller", category="fit", kcal=430, protein=25.0, carbs=65.0, fat=5.0, ingredients="Kartoffeln, Kräuterquark, Leinöl", instructions="1. 400g Kartoffeln waschen und 20 Minuten in Salzwasser kochen. 2. 200g Magerquark mit 2 EL Milch glatt rühren. 3. Eine Handvoll Kräuter (Schnittlauch, Petersilie) hacken und unter den Quark mischen. 4. Mit Salz, Pfeffer und 1 TL Zitronensaft würzen. 5. Kartoffeln abgießen, pellen. 6. Mit Kräuterquark und 1 EL Leinöl servieren."),
        Recipe(name="Wrap: Hähnchen & Caesar", category="build", kcal=580, protein=42.0, carbs=45.0, fat=22.0, ingredients="Wrap, Hähnchen, Parmesan", instructions="1. 150g Hähnchenbrust waschen, trocken tupfen, mit Salz und Pfeffer würzen. 2. 1 TL Öl erhitzen und das Hähnchen 6 Minuten pro Seite braten, dann in Streifen schneiden. 3. Den Wrap erwärmen. 4. 2 EL Joghurt-Caesar-Dressing mit 1 TL Parmesan auf dem Wrap verstreichen. 5. Hähnchenstreifen und Salat darauf geben. 6. Fest einrollen, in der Pfanne kurz anbraten und halbieren."),
        Recipe(name="Protein-Müsli-Beeren", category="fit", kcal=390, protein=30.0, carbs=50.0, fat=6.0, ingredients="Haferflocken, Whey, Milch, Beeren", instructions="1. 40g Haferflocken in eine Schüssel geben. 2. 25g Whey Protein zugeben. 3. 100g gemischte Beeren waschen. 4. 200ml Milch dazugießen. 5. Alles gut verrühren. 6. 5 Minuten quellen lassen und mit den Beeren toppen."),
        Recipe(name="Gebratener Reis (Tofu)", category="fit", kcal=470, protein=25.0, carbs=75.0, fat=10.0, ingredients="Reis, Tofu, Gemüse", instructions="1. 100g Reis kochen und abkühlen lassen. 2. 150g Tofu abtupfen und würfeln. 3. 1 EL Sesamöl im Wok erhitzen, Tofu 5 Minuten kross braten, herausnehmen. 4. 150g gemischtes Gemüse (Paprika, Zucchini, Karotte) im Wok 5 Minuten braten. 5. Den Reis und 2 EL Sojasauce zugeben, 3 Minuten unter Rühren braten. 6. Tofu zurückgeben, mit Frühlingszwiebeln servieren."),
        Recipe(name="Linsen-Eintopf-Fitness", category="fit", kcal=440, protein=30.0, carbs=65.0, fat=4.0, ingredients="Linsen, Kartoffeln, Karotten", instructions="1. 150g rote Linsen abspülen. 2. 2 Kartoffeln schälen und würfeln, 2 Karotten in Scheiben schneiden. 3. Eine Zwiebel hacken und in 1 TL Öl glasig dünsten. 4. 800ml Gemüsebrühe, Linsen, Kartoffeln und Karotten zugeben. 5. 25 Minuten köcheln lassen, mit Salz, Pfeffer und Majoran würzen. 6. Mit Petersilie bestreuen und servieren."),
        Recipe(name="Rührei mit Schinken", category="lose", kcal=340, protein=32.0, carbs=2.0, fat=22.0, ingredients="3 Eier, 50g Schinken", instructions="1. 3 Eier mit 2 EL Milch, Salz und Pfeffer verquirlen. 2. 50g Kochschinken in Streifen schneiden. 3. 1 TL Butter in einer Pfanne erhitzen. 4. Die Eier hineingießen und bei niedriger Hitze langsam stocken lassen. 5. Den Schinken zugeben und unterheben. 6. Mit Schnittlauch bestreut servieren."),
        Recipe(name="Bowl: Steak & Avocado", category="build", kcal=720, protein=52.0, carbs=60.0, fat=35.0, ingredients="Reis, Steak, Avocado, Mais", instructions="1. 100g Reis in Salzwasser 12 Minuten kochen. 2. 150g Rindersteak trocken tupfen, mit Salz und Pfeffer würzen. 3. 1 EL Butterschmalz erhitzen und das Steak 3 Minuten pro Seite scharf braten, 5 Minuten ruhen lassen. 4. Avocado halbieren und in Scheiben schneiden. 5. Mais abgießen. 6. Reis in eine Bowl geben, Steak in Streifen schneiden, mit Avocado und Mais anrichten."),
        Recipe(name="Smoothie: Schoko & Erdnuss", category="build", kcal=510, protein=32.0, carbs=40.0, fat=25.0, ingredients="Whey, Milch, Mus, Kakao", instructions="1. 35g Whey Schoko, 1 EL Erdnussmus, 1 TL Kakaopulver und 300ml Milch in den Mixer geben. 2. Eine halbe Banane zugeben. 3. 3 Eiswürfel zugeben. 4. 60 Sekunden cremig mixen. 5. In ein Glas gießen und genießen."),
        Recipe(name="Salat: Mozzarella & Tomate", category="lose", kcal=380, protein=25.0, carbs=10.0, fat=28.0, ingredients="Mozzarella-Light, Tomaten", instructions="1. 125g Mozzarella-Light in Scheiben schneiden. 2. 3 große Tomaten in Scheiben schneiden. 3. Abwechselnd Tomaten und Mozzarella auf einem Teller anrichten. 4. Mit Salz, Pfeffer und 1 TL Oregano bestreuen. 5. 2 EL Olivenöl und 1 EL Balsamico-Essig darübergießen. 6. Mit frischem Basilikum garnieren."),
        Recipe(name="Putenbrust mit Reis", category="fit", kcal=460, protein=42.0, carbs=60.0, fat=5.0, ingredients="Pute, Reis, Erbsen", instructions="1. 80g Reis in Salzwasser kochen. 2. 150g Putenbrust waschen, trocken tupfen und in Streifen schneiden. Mit Salz, Pfeffer und Paprikapulver würzen. 3. 1 TL Öl erhitzen und die Pute 5 Minuten braten. 4. 80g Erbsen in kochendem Wasser 3 Minuten garen. 5. Reis auf einem Teller anrichten. 6. Pute und Erbsen darauf geben und servieren."),
        Recipe(name="Fischfilet & Kartoffelbrei", category="fit", kcal=490, protein=38.0, carbs=65.0, fat=12.0, ingredients="Dorsch, Kartoffeln, Milch-Light", instructions="1. 300g Kartoffeln schälen und in Salzwasser 20 Minuten kochen. 2. 200g Dorschfilet waschen, trocken tupfen, mit Zitronensaft, Salz und Pfeffer würzen. 3. Den Fisch in einer Pfanne mit 1 TL Öl 4 Minuten pro Seite braten. 4. Kartoffeln abgießen, mit 50ml Milch-Light und 1 TL Butter stampfen. 5. Mit Muskat, Salz und Pfeffer würzen. 6. Kartoffelbrei und Fisch auf einem Teller anrichten."),
        Recipe(name="Bowl: Hähnchen & Hummus", category="fit", kcal=540, protein=40.0, carbs=55.0, fat=18.0, ingredients="Couscous, Hähnchen, Hummus", instructions="1. 80g Couscous mit 120ml kochendem Wasser und 1 Prise Salz 5 Minuten quellen lassen. 2. 150g Hähnchenbrust waschen, würfeln, mit Salz und Pfeffer würzen. 3. 1 TL Öl erhitzen und das Hähnchen 6 Minuten braten. 4. 3 EL Hummus in einer Schale glatt rühren. 5. Couscous in eine Bowl geben, Hähnchen und Hummus darauf anrichten. 6. Mit Paprikapulver bestreuen und servieren."),
        Recipe(name="Pasta mit Garnelen", category="fit", kcal=480, protein=35.0, carbs=70.0, fat=8.0, ingredients="Pasta, Garnelen, Knoblauch", instructions="1. 100g Vollkornpasta in Salzwasser bissfest kochen. 2. 150g Garnelen schälen und waschen. 3. 2 Knoblauchzehen hacken und in 1 EL Olivenöl glasig dünsten. 4. Die Garnelen zugeben und 3 Minuten braten, mit Salz, Pfeffer und Chili würzen. 5. 100ml Weißwein oder Brühe angißen und 2 Minuten reduzieren. 6. Pasta abgießen, mit Garnelen vermengen und mit Petersilie servieren."),
        Recipe(name="Skyr mit Nüssen & Honig", category="fit", kcal=390, protein=32.0, carbs=35.0, fat=15.0, ingredients="Skyr, Walnüsse, Honig", instructions="1. 250g Skyr in eine Schale geben. 2. 30g Walnüsse grob hacken. 3. Die Walnüsse in einer trockenen Pfanne 2 Minuten rösten. 4. 1 EL Honig über den Skyr träufeln. 5. Die gerösteten Walnüsse darauf verteilen. 6. Nach Wunsch mit einer Prise Zimt bestreuen."),
        Recipe(name="Wrap: Thunfisch & Mais", category="fit", kcal=430, protein=35.0, carbs=45.0, fat=12.0, ingredients="Wrap, Thunfisch, Mais", instructions="1. Die Dose Thunfisch abgießen und mit einer Gabel zerkleinern. 2. 2 EL Mais abgießen und zum Thunfisch geben. 3. 1 EL Joghurt, Salz und Pfeffer zugeben und verrühren. 4. Den Wrap erwärmen. 5. Die Thunfisch-Mais-Mischung auf dem Wrap verteilen, etwas Salat zugeben. 6. Fest einrollen, halbieren und servieren."),
        Recipe(name="Beef-Burger (Fitness)", category="build", kcal=650, protein=48.0, carbs=55.0, fat=25.0, ingredients="Vollkornbun, Rind, Salat", instructions="1. 150g Rinderhack mit Salz, Pfeffer und 1 TL Senf würzen, zu einem Patty formen. 2. 1 TL Öl in einer Pfanne erhitzen und das Patty 5 Minuten pro Seite braten. 3. Das Vollkornbun aufschneiden und kurz toasten. 4. Die untere Hälfte mit Salat belegen. 5. Das Patty darauf setzen, nach Wunsch mit Tomatenscheiben und Zwiebelringen toppen. 6. Den Burger zusammenklappen und servieren."),
        Recipe(name="Linsensalat mit Feta", category="fit", kcal=410, protein=25.0, carbs=40.0, fat=15.0, ingredients="Linsen, Feta, Paprika", instructions="1. 150g braune Linsen 20 Minuten in Salzwasser kochen, abgießen und abkühlen lassen. 2. Eine Paprika entkernen und würfeln. 3. 80g Feta zerbröseln. 4. 2 EL Essig mit 1 EL Olivenöl, Salz und Pfeffer verrühren. 5. Linsen, Paprika und Feta vermengen. 6. Mit dem Dressing übergießen und kalt servieren."),
        Recipe(name="Hähnchen-Spieße & Bulgur", category="fit", kcal=520, protein=40.0, carbs=60.0, fat=12.0, ingredients="Hähnchen, Bulgur, Paprika", instructions="1. 80g Bulgur mit 160ml kochendem Wasser 10 Minuten quellen lassen. 2. 150g Hähnchenbrust in Würfel schneiden, mit Salz, Pfeffer und 1 TL Paprikapulver würzen. 3. Eine Paprika in Stücke schneiden. 4. Hähnchen und Paprika abwechselnd auf Spieße stecken. 5. 1 EL Öl erhitzen und die Spieße rundherum 10 Minuten braten. 6. Mit Bulgur servieren."),
        Recipe(name="Quark mit Beeren-Mix", category="lose", kcal=240, protein=35.0, carbs=20.0, fat=1.0, ingredients="Quark, TK-Beeren", instructions="1. 250g Magerquark in eine Schüssel geben. 2. 150g TK-Beeren antauen lassen. 3. 1 TL Honig oder Süßstoff zum Quark geben. 4. Die Beeren unter den Quark heben. 5. Nach Wunsch mit 1 EL Haferflocken toppen. 6. Gut verrühren und genießen."),
        Recipe(name="Pasta: Spinat & Lachs", category="fit", kcal=590, protein=35.0, carbs=75.0, fat=18.0, ingredients="Pasta, Spinat, Lachs", instructions="1. 100g Pasta in Salzwasser kochen. 2. 150g Lachs waschen, würfeln, mit Salz und Pfeffer würzen. 3. 1 TL Öl erhitzen und den Lachs 4 Minuten braten. 4. 100g frischen Spinat waschen und 2 Minuten zusammenfallen lassen. 5. 2 EL Frischkäse-Light unter den Spinat rühren. 6. Pasta abgießen, mit Lachs und Spinat vermengen."),
        Recipe(name="Bowl: Falafel & Couscous", category="lose", kcal=480, protein=15.0, carbs=70.0, fat=18.0, ingredients="Falafel, Couscous, Gurke", instructions="1. 80g Couscous mit 120ml kochendem Wasser 5 Minuten quellen lassen. 2. 6 Falafel im Backofen bei 180°C 8 Minuten backen. 3. Eine Gurke waschen und würfeln. 4. 2 EL Joghurt mit 1 TL Zitronensaft verrühren. 5. Couscous in eine Bowl geben, Falafel und Gurke darauf anrichten. 6. Mit dem Joghurt-Dressing beträufeln."),
        Recipe(name="Putengeschnetzeltes Reis", category="fit", kcal=530, protein=42.0, carbs=65.0, fat=10.0, ingredients="Pute, Reis, Champignons", instructions="1. 80g Reis in Salzwasser kochen. 2. 150g Putenbrust in Streifen schneiden, mit Salz und Pfeffer würzen. 3. 150g Champignons putzen und in Scheiben schneiden. 4. 1 TL Öl erhitzen, die Pute 3 Minuten scharf anbraten, herausnehmen. 5. Pilze im Bratensatz 5 Minuten braten, 100ml Brühe angißen und 1 EL Schmand-Light einrühren. 6. Pute zurückgeben, mit Reis servieren."),
        Recipe(name="Rührei mit Tomaten", category="lose", kcal=280, protein=22.0, carbs=5.0, fat=18.0, ingredients="3 Eier, Kirschtomaten", instructions="1. 6 Kirschtomaten waschen und halbieren. 2. 1 TL Öl in einer Pfanne erhitzen und die Tomaten 2 Minuten anbraten, herausnehmen. 3. 3 Eier mit 2 EL Milch, Salz und Pfeffer verquirlen. 4. 1 TL Butter in der Pfanne schmelzen, die Eier hineingießen. 5. Bei niedriger Hitze langsam stocken lassen, dabei die Tomaten unterheben. 6. Mit frischen Kräutern bestreut servieren."),
        Recipe(name="Smoothie: Banane & Zimt", category="fit", kcal=310, protein=25.0, carbs=45.0, fat=3.0, ingredients="Banane, Whey, Zimt, Milch", instructions="1. Eine Banane schälen und in Stücke brechen. 2. 25g Whey Vanille, 200ml Milch, 1 TL Honig und 1 TL Zimt in den Mixer geben. 3. 3 Eiswürfel zugeben. 4. 45 Sekunden cremig mixen. 5. In ein Glas gießen, mit einer Prise Zimt bestreuen und servieren."),
        Recipe(name="Salat: Thunfisch & Olive", category="lose", kcal=340, protein=38.0, carbs=8.0, fat=18.0, ingredients="Thunfisch, Salat, Oliven", instructions="1. Die Dose Thunfisch abgießen und mit einer Gabel zerpflücken. 2. 150g gemischten Salat waschen und trocken schleudern. 3. 50g schwarze Oliven in Scheiben schneiden. 4. 2 EL Essig mit 1 EL Olivenöl, Salz und Pfeffer verrühren. 5. Alles in einer Schüssel vermengen. 6. Mit dem Dressing servieren."),
        Recipe(name="Wrap: Hähnchen & Paprika", category="fit", kcal=410, protein=35.0, carbs=40.0, fat=10.0, ingredients="Wrap, Hähnchen, Paprika", instructions="1. 120g Hähnchenbrust in Streifen schneiden, mit Salz und Pfeffer würzen. 2. 1 TL Öl erhitzen und das Hähnchen 5 Minuten braten. 3. Eine Paprika entkernen und in Streifen schneiden. 4. Den Wrap erwärmen und mit 2 EL Joghurt bestreichen. 5. Hähnchen und Paprika auf dem Wrap verteilen. 6. Fest einrollen, halbieren und servieren."),
        Recipe(name="Rindersteak & Spargel", category="fit", kcal=460, protein=50.0, carbs=8.0, fat=25.0, ingredients="Steak, grüner Spargel", instructions="1. 200g grünen Spargel waschen, holzige Enden entfernen. 2. 150g Rindersteak trocken tupfen, mit Salz und Pfeffer würzen. 3. 1 EL Öl in einer Grillpfanne erhitzen, das Steak 3 Minuten pro Seite braten, ruhen lassen. 4. Den Spargel im Bratensatz 6-8 Minuten unter Wenden braten. 5. Das Steak in Streifen schneiden. 6. Mit Spargel anrichten."),
        Recipe(name="Skyr mit Mandeln", category="fit", kcal=350, protein=35.0, carbs=20.0, fat=12.0, ingredients="Skyr, Mandeln", instructions="1. 250g Skyr in eine Schale geben. 2. 20g Mandelblättchen in einer trockenen Pfanne goldbraun rösten. 3. Den Skyr glatt rühren. 4. Die Mandeln darüber streuen. 5. Nach Wunsch mit 1 TL Honig süßen. 6. Mit frischen Beeren toppen und servieren."),
        Recipe(name="Linsensuppe Fitness", category="lose", kcal=380, protein=28.0, carbs=55.0, fat=4.0, ingredients="Linsen, Suppengrün", instructions="1. 200g rote Linsen abspülen. 2. 1 Zwiebel, 2 Karotten, 1 Stück Sellerie würfeln. 3. 1 TL Öl erhitzen und das Gemüze 5 Minuten anschwitzen. 4. 800ml Gemüsebrühe und die Linsen zugeben. 5. 20 Minuten köcheln lassen, mit Salz, Pfeffer und Majoran würzen. 6. Mit Petersilie bestreuen und servieren."),
        Recipe(name="Pasta mit Pesto (light)", category="fit", kcal=510, protein=15.0, carbs=80.0, fat=18.0, ingredients="Pasta, Pesto-Light", instructions="1. 120g Pasta in Salzwasser bissfest kochen. 2. 2 EL Pesto-Light in einer Schüssel bereitstellen. 3. 1 EL Nudelwasser zum Pesto geben und verrühren. 4. Die Pasta abgießen und direkt zum Pesto geben. 5. Alles gut vermengen. 6. Nach Wunsch mit Cherrytomaten und Parmesan servieren."),
        Recipe(name="Hähnchenbrust & Brokkoli", category="lose", kcal=320, protein=45.0, carbs=10.0, fat=8.0, ingredients="Hähnchen, Brokkoli", instructions="1. 200g Hähnchenbrust waschen, trocken tupfen, mit Salz und Pfeffer würzen. 2. 1 TL Öl erhitzen und das Hähnchen 6 Minuten pro Seite braten. 3. 200g Brokkoli in Röschen teilen. 4. Den Brokkoli 5 Minuten in Salzwasser garen. 5. Das Hähnchen in Scheiben schneiden. 6. Mit Brokkoli anrichten und mit Zitronensaft beträufeln."),
        Recipe(name="Süßkartoffelpommes & Quark", category="fit", kcal=420, protein=12.0, carbs=70.0, fat=10.0, ingredients="Süßkartoffel, Quark", instructions="1. Den Backofen auf 200°C Umluft vorheizen. 2. Eine Süßkartoffel waschen und in Pommes-Streifen schneiden. 3. Mit 1 EL Olivenöl, Salz, Paprikapulver und Rosmarin vermengen. 4. Auf ein Backblech legen und 25 Minuten backen. 5. 150g Magerquark mit Schnittlauch, Salz und Pfeffer verrühren. 6. Pommes mit dem Kräuterquark dippen."),
        Recipe(name="Bowl: Tofu & Edamame", category="fit", kcal=450, protein=30.0, carbs=50.0, fat=12.0, ingredients="Tofu, Reis, Edamame", instructions="1. 80g Reis kochen. 2. 150g Tofu abtupfen und würfeln. 3. 1 EL Sesamöl erhitzen und den Tofu 6 Minuten kross braten, mit 1 EL Sojasauce ablöschen. 4. 80g Edamame in kochendem Wasser 3 Minuten garen. 5. Reis in eine Bowl geben. 6. Tofu und Edamame darauf anrichten, mit Sesam bestreuen."),
        Recipe(name="Wrap: Lachs & Avocado", category="build", kcal=610, protein=32.0, carbs=40.0, fat=35.0, ingredients="Wrap, Lachs, Avocado", instructions="1. 100g Räucherlachs in Streifen zupfen. 2. Eine Avocado halbieren, entkernen und in Scheiben schneiden. 3. Den Wrap erwärmen und mit 2 EL Frischkäse-Light bestreichen. 4. Lachs und Avocado auf dem Wrap verteilen. 5. Nach Wunsch etwas Rucola zugeben. 6. Fest einrollen, halbieren und servieren."),
        Recipe(name="Omelette: Schinken & Käse", category="fit", kcal=420, protein=35.0, carbs=5.0, fat=28.0, ingredients="3 Eier, Schinken, Käse", instructions="1. 3 Eier mit Salz, Pfeffer und 1 EL Milch verquirlen. 2. 50g Kochschinken in Streifen schneiden, 30g Käse reiben. 3. 1 TL Butter in einer Pfanne erhitzen, die Eier hineingießen. 4. Bei niedriger Hitze stocken lassen, Schinken und Käse auf der noch flüssigen Oberseite verteilen. 5. Das Omelette zusammenklappen. 6. 1 Minute weitergaren und servieren."),
        Recipe(name="Protein-Porridge Beeren", category="fit", kcal=430, protein=30.0, carbs=60.0, fat=8.0, ingredients="Hafer, Whey, Beeren", instructions="1. 50g Haferflocken mit 200ml Milch in einem Topf verrühren. 2. Bei mittlerer Hitze unter Rühren 3-4 Minuten cremig kochen. 3. Vom Herd nehmen und 25g Whey Protein einrühren. 4. 100g Beeren waschen. 5. Porridge in eine Schale geben. 6. Mit den Beeren toppen und servieren."),
        Recipe(name="Rindersteak & Kartoffeln", category="build", kcal=690, protein=52.0, carbs=55.0, fat=28.0, ingredients="Steak, Kartoffeln", instructions="1. 300g Kartoffeln waschen und in Salzwasser 20 Minuten kochen. 2. 200g Rindersteak trocken tupfen, mit Salz und Pfeffer würzen. 3. 1 EL Butterschmalz erhitzen, das Steak 3-4 Minuten pro Seite braten, 5 Minuten ruhen lassen. 4. Die Kartoffeln abgießen und halbieren. 5. Die Kartoffeln im Bratensatz 3 Minuten braten. 6. Das Steak aufschneiden und mit Kartoffeln servieren."),
        Recipe(name="Thunfisch-Salat (classic)", category="lose", kcal=290, protein=42.0, carbs=5.0, fat=10.0, ingredients="Thunfisch, Salat, Gurke", instructions="1. Die Dose Thunfisch abgießen. 2. 150g gemischten Salat waschen. 3. Eine halbe Gurke waschen und in Scheiben schneiden. 4. 2 EL Essig mit 1 EL Olivenöl, Salz und Pfeffer verrühren. 5. Alles in einer Schüssel vermengen. 6. Mit dem Dressing servieren."),
        Recipe(name="Chicken-Wrap Joghurt", category="fit", kcal=390, protein=35.0, carbs=40.0, fat=8.0, ingredients="Wrap, Hähnchen, Joghurt", instructions="1. 120g Hähnchenbrust in Streifen schneiden, mit Salz, Pfeffer und Curry würzen. 2. 1 TL Öl erhitzen und das Hähnchen 5 Minuten braten. 3. 3 EL Joghurt mit 1 TL Zitronensaft und Salz verrühren. 4. Den Wrap erwärmen und mit Joghurt bestreichen. 5. Hähnchen und Salat darauf geben. 6. Fest einrollen, halbieren und servieren."),
        Recipe(name="Pasta: Thunfisch & Olive", category="build", kcal=640, protein=40.0, carbs=85.0, fat=15.0, ingredients="Pasta, Thunfisch, Oliven", instructions="1. 120g Pasta in Salzwasser kochen. 2. Die Dose Thunfisch abgießen. 3. 50g Oliven in Scheiben schneiden. 4. 2 EL Olivenöl mit 1 Knoblauchzehe in einer Pfanne erwärmen. 5. Thunfisch und Oliven zugeben und kurz erwärmen. 6. Pasta abgießen, mit der Sauce vermengen und servieren."),
        Recipe(name="Bowl: Hähnchen & Avocado", category="build", kcal=710, protein=45.0, carbs=65.0, fat=30.0, ingredients="Reis, Hähnchen, Avocado", instructions="1. 100g Reis kochen. 2. 150g Hähnchenbrust würfeln, mit Salz, Pfeffer und 1 TL Kreuzkümmel würzen. 3. 1 TL Öl erhitzen und das Hähnchen 6 Minuten braten. 4. Eine Avocado in Scheiben schneiden. 5. 2 EL Salsa vorbereiten. 6. Reis in eine Bowl geben, Hähnchen, Avocado und Salsa darauf anrichten."),
        Recipe(name="Smoothie: Heidelbeer Whey", category="lose", kcal=260, protein=26.0, carbs=30.0, fat=2.0, ingredients="Heidelbeeren, Whey", instructions="1. 100g Heidelbeeren waschen. 2. 25g Whey Protein, 200ml Wasser und die Heidelbeeren in den Mixer geben. 3. 1 TL Zitronensaft zugeben. 4. 45 Sekunden mixen. 5. In ein Glas gießen und genießen."),
        Recipe(name="Salat: Feta & Melone", category="lose", kcal=220, protein=12.0, carbs=35.0, fat=10.0, ingredients="Feta, Wassermelone", instructions="1. 200g Wassermelone entkernen und in Würfel schneiden. 2. 80g Feta in Würfel schneiden. 3. Eine Handvoll Minze waschen. 4. 1 EL Olivenöl mit 1 EL Limettensaft verrühren. 5. Melone und Feta auf einem Teller anrichten. 6. Mit Minze bestreuen und Dressing darübergießen."),
        Recipe(name="Putensteak & Zucchini", category="lose", kcal=280, protein=42.0, carbs=10.0, fat=8.0, ingredients="Pute, Zucchini", instructions="1. 180g Putensteak waschen, trocken tupfen, mit Salz und Pfeffer würzen. 2. 1 TL Öl erhitzen und das Steak 5 Minuten pro Seite braten. 3. 2 Zucchini waschen und längs in Scheiben schneiden. 4. Die Zucchini im Bratensatz 4 Minuten pro Seite braten. 5. Das Steak in Streifen schneiden. 6. Mit Zucchini anrichten."),
        Recipe(name="Linsensalat mit Apfel", category="fit", kcal=390, protein=22.0, carbs=60.0, fat=6.0, ingredients="Linsen, Apfel", instructions="1. 150g braune Linsen 20 Minuten kochen, abgießen und abkühlen. 2. Einen Apfel waschen, entkernen und würfeln. 3. 2 EL Essig mit 1 EL Olivenöl, Salz und Pfeffer verrühren. 4. Linsen und Apfel vermengen. 5. Dressing darübergießen. 6. Mit Walnüssen bestreut servieren."),
        Recipe(name="Hähnchen Curry & Reis", category="build", kcal=620, protein=42.0, carbs=85.0, fat=12.0, ingredients="Hähnchen, Reis, Curry", instructions="1. 100g Reis kochen. 2. 200g Hähnchenbrust würfeln. 3. Eine Zwiebel hacken, in 1 TL Öl glasig dünsten. 2 TL Currypulver zugeben. 4. 200ml Kokosmilch-Light, das Hähnchen zugeben und 15 Minuten köcheln. 5. Mit Salz und Pfeffer abschmecken. 6. Mit Reis servieren."),
        Recipe(name="Rührei: Spinat & Tomate", category="lose", kcal=290, protein=24.0, carbs=6.0, fat=18.0, ingredients="3 Eier, Spinat, Tomate", instructions="1. 100g frischen Spinat waschen. 2. Eine Tomate würfeln. 3. 1 TL Öl erhitzen, den Spinat 2 Minuten zusammenfallen lassen. 4. 3 Eier mit Salz und Pfeffer verquirlen, über den Spinat gießen. 5. Bei niedriger Hitze stocken lassen, Tomatenwürfel zugeben. 6. Mit Kräutern bestreut servieren."),
        Recipe(name="Bowl: Tofu & Bulgur", category="fit", kcal=480, protein=25.0, carbs=70.0, fat=12.0, ingredients="Tofu, Bulgur, Paprika", instructions="1. 80g Bulgur mit 160ml kochendem Wasser 10 Minuten quellen. 2. 150g Tofu würfeln und in 1 EL Sojasauce marinieren. 3. 1 EL Sesamöl erhitzen und den Tofu 6 Minuten kross braten. 4. Eine Paprika entkernen und würfeln. 5. Bulgur in eine Bowl geben. 6. Tofu und Paprika darauf anrichten."),
        Recipe(name="Wrap: Pute & Salat", category="lose", kcal=350, protein=32.0, carbs=35.0, fat=8.0, ingredients="Wrap, Pute, Salat", instructions="1. 120g Putenbrust in Streifen schneiden, mit Salz und Pfeffer würzen. 2. 1 TL Öl erhitzen und die Pute 5 Minuten braten. 3. Den Wrap erwärmen und mit 2 EL Joghurt bestreichen. 4. Salat waschen und auf dem Wrap verteilen. 5. Die Pute darauf geben. 6. Fest einrollen, halbieren und servieren."),
        Recipe(name="Pasta: Garnelen & Zitrone", category="fit", kcal=520, protein=35.0, carbs=75.0, fat=10.0, ingredients="Pasta, Garnelen, Zitrone", instructions="1. 100g Pasta in Salzwasser kochen. 2. 150g Garnelen schälen und waschen. 3. 1 EL Olivenöl erhitzen, 2 Knoblauchzehen hacken und kurz braten. 4. Garnelen zugeben und 3 Minuten braten, mit Salz und Pfeffer würzen. 5. Saft einer Zitrone und 2 EL Petersilie zugeben. 6. Pasta abgießen, mit Garnelen vermengen."),
        Recipe(name="Skyr mit Erdbeeren", category="lose", kcal=230, protein=35.0, carbs=20.0, fat=1.0, ingredients="Skyr, Erdbeeren", instructions="1. 250g Skyr in eine Schale geben. 2. 150g Erdbeeren waschen, putzen und vierteln. 3. Den Skyr glatt rühren. 4. Die Erdbeeren darauf anrichten. 5. Nach Wunsch mit 1 TL Honig süßen. 6. Mit Minze garnieren und servieren."),
        Recipe(name="Beef & Broccoli Wok", category="fit", kcal=440, protein=45.0, carbs=15.0, fat=22.0, ingredients="Rind, Brokkoli, Soja", instructions="1. 150g Rindfleisch in dünne Streifen schneiden. 2. 200g Brokkoli in Röschen teilen. 3. 1 EL Sesamöl im Wok erhitzen, das Fleisch 3 Minuten scharf anbraten, herausnehmen. 4. Den Brokkoli 4 Minuten im Wok braten. 5. 2 EL Sojasauce, 1 TL Honig und 1cm Ingwer zugeben. 6. Fleisch zurückgeben, vermengen und servieren."),
        Recipe(name="Kartoffelpfanne mit Ei", category="fit", kcal=410, protein=22.0, carbs=60.0, fat=10.0, ingredients="Kartoffel, 2 Eier", instructions="1. 300g Kartoffeln waschen, in Scheiben schneiden und 10 Minuten in Salzwasser vorkochen. 2. 1 EL Öl in einer Pfanne erhitzen und die Kartoffelscheiben 10 Minuten goldbraun braten. 3. 2 Eier mit Salz und Pfeffer verquirlen. 4. Die Eier über die Kartoffeln gießen. 5. Bei niedriger Hitze stocken lassen, bis die Eier fest sind. 6. Mit Schnittlauch bestreuen."),
        Recipe(name="Smoothie: Mango & Kokos", category="lose", kcal=290, protein=24.0, carbs=40.0, fat=2.0, ingredients="Mango, Whey, Kokos", instructions="1. 150g Mango in Stücke schneiden. 2. 25g Whey Vanille, 200ml Kokoswasser und die Mango in den Mixer geben. 3. 1 TL Limettensaft zugeben. 4. 45 Sekunden mixen. 5. In ein Glas gießen und genießen."),
        Recipe(name="Salat: Pute & Karotte", category="lose", kcal=270, protein=35.0, carbs=15.0, fat=8.0, ingredients="Pute, Karotte, Salat", instructions="1. 120g Putenbrust waschen, trocken tupfen und in Streifen schneiden. 2. 1 TL Öl erhitzen und die Pute 5 Minuten braten, mit Salz und Pfeffer würzen. 3. 2 Karotten schälen und raspeln. 4. 150g Salat waschen. 5. 2 EL Essig mit 1 EL Öl verrühren. 6. Alles vermengen und mit Dressing servieren."),
        Recipe(name="Wrap: Beef & Beans", category="build", kcal=650, protein=42.0, carbs=75.0, fat=22.0, ingredients="Wrap, Rind, Bohnen", instructions="1. 120g Rinderhack mit Salz, Pfeffer und 1 TL Kreuzkümmel würzen. 2. 1 TL Öl erhitzen und das Hack 5 Minuten krümelig braten. 3. 80g Kidneybohnen abgießen und zum Hack geben, 2 Minuten erwärmen. 4. Den Wrap erwärmen. 5. Die Hack-Bohnen-Mischung auf dem Wrap verteilen, Salat zugeben. 6. Fest einrollen und in der Pfanne kurz anbraten."),
        Recipe(name="Pasta: Pute & Pilze", category="build", kcal=680, protein=45.0, carbs=85.0, fat=15.0, ingredients="Pasta, Pute, Pilze", instructions="1. 120g Pasta in Salzwasser kochen. 2. 150g Putenbrust in Streifen schneiden. 3. 200g Champignons in Scheiben schneiden. 4. 1 TL Öl erhitzen, die Pute 4 Minuten braten, herausnehmen. 5. Pilze 5 Minuten im Bratensatz braten, 100ml Sahne-Light angißen. 6. Pute zurückgeben, Pasta abgießen, alles vermengen und servieren."),
        Recipe(name="Bowl: Lachs & Quinoa", category="fit", kcal=590, protein=35.0, carbs=60.0, fat=22.0, ingredients="Lachs, Quinoa", instructions="1. 80g Quinoa abspülen und mit 160ml Wasser 15 Minuten quellen lassen. 2. 150g Lachsfilet waschen, mit Zitronensaft, Salz und Pfeffer würzen. 3. 1 TL Öl erhitzen und den Lachs 4 Minuten pro Seite braten. 4. 100g Babyspinat waschen. 5. Quinoa in eine Bowl geben. 6. Spinat und Lachs darauf anrichten."),
        Recipe(name="Skyr mit Walnüssen", category="fit", kcal=380, protein=32.0, carbs=15.0, fat=24.0, ingredients="Skyr, Walnüsse", instructions="1. 250g Skyr in eine Schale geben. 2. 30g Walnüsse grob hacken. 3. In einer trockenen Pfanne 2 Minuten rösten. 4. 1 EL Honig über den Skyr träufeln. 5. Die Walnüsse darauf verteilen. 6. Servieren."),
        Recipe(name="Hähnchenbrust & Tomate", category="lose", kcal=290, protein=45.0, carbs=10.0, fat=6.0, ingredients="Hähnchen, Tomaten", instructions="1. 200g Hähnchenbrust waschen, trocken tupfen, mit Salz und Pfeffer würzen. 2. 1 TL Öl erhitzen und das Hähnchen 6 Minuten pro Seite braten, in Streifen schneiden. 3. 3 Tomaten in Scheiben schneiden. 4. 150g gemischten Salat waschen. 5. Salat und Tomaten auf einem Teller anrichten. 6. Hähnchen darauf geben und mit 2 EL Joghurt-Dressing servieren."),
        
        // --- NEU: CHEFKOCH-INSPIRIERTE REZEPTE ---
        
        // --- FRÜHSTÜCK (für alle) ---
        Recipe(name="Baked Feta Eggs", category="fit", kcal=350, protein=28.0, carbs=5.0, fat=25.0, ingredients="3 Eier, 50g Feta, 100g Kirschtomaten, 1 TL Olivenöl", instructions="1. Den Backofen auf 200°C Umluft vorheizen. 2. 100g Kirschtomaten waschen und halbieren, 50g Feta in der Mitte einer kleinen Auflaufform platzieren. 3. Mit 1 TL Olivenöl beträufeln und mit Oregano, Salz und Pfeffer bestreuen. 4. 15 Minuten backen, bis der Feta weich ist. 5. 3 Eier um den Feta herum aufschlagen und weitere 8-10 Minuten backen, bis das Eiweiß gestockt ist. 6. Mit frischem Basilikum bestreuen und mit Vollkornbrot servieren."),
        Recipe(name="Protein-Bounty-Porridge", category="fit", kcal=420, protein=32.0, carbs=55.0, fat=14.0, ingredients="50g Haferflocken, 200ml Milch, 25g Whey Schoko, 1 EL Kokosraspel", instructions="1. 50g Haferflocken mit 200ml Milch in einem Topf verrühren. 2. Bei mittlerer Hitze 3-4 Minuten cremig kochen. 3. Vom Herd nehmen und 25g Whey Schoko unterrühren. 4. 1 EL Kokosraspel und 1 TL Kakaopulver einrühren. 5. In eine Schale geben und mit 1 EL gehackter Zartbitterschokolade toppen. 6. Nach Wunsch mit Kokosraspeln bestreuen."),
        Recipe(name="Magerquark-Keulchen", category="fit", kcal=380, protein=32.0, carbs=40.0, fat=8.0, ingredients="200g Magerquark, 2 Eier, 50g Haferflocken, 1 EL Honig", instructions="1. 200g Magerquark, 2 Eier, 50g Haferflocken, 1 EL Honig und 1 Prise Salz in einer Schüssel zu einem glatten Teig verrühren. 2. 1 TL Kokosöl in einer beschichteten Pfanne erhitzen. 3. Aus dem Teig 8 kleine Keulchen formen und bei mittlerer Hitze 3-4 Minuten pro Seite goldbraun braten. 4. Auf Küchenpapier abtropfen lassen. 5. Mit frischen Beeren oder Apfelmus servieren. 6. Nach Wunsch mit Zimt bestreuen."),
        Recipe(name="Protein-Apple-Crumble", category="fit", kcal=340, protein=25.0, carbs=50.0, fat=7.0, ingredients="2 Äpfel, 30g Whey Vanille, 30g Haferflocken, 1 EL Mandeln", instructions="1. Den Backofen auf 180°C Umluft vorheizen. 2. 2 Äpfel waschen, entkernen und in kleine Würfel schneiden. 3. Die Apfelwürfel mit 1 TL Zimt und 1 TL Honig vermengen und in eine Auflaufform geben. 4. 30g Haferflocken, 30g Whey Vanille und 1 EL gehackte Mandeln mit 1 EL Butter verkneten. 5. Den Streusel über die Äpfel geben. 6. 15-18 Minuten backen, bis die Streusel goldbraun sind. Lauwarm mit 2 EL Skyr servieren."),
        Recipe(name="Avocado-Bohnen-Toast", category="fit", kcal=380, protein=18.0, carbs=35.0, fat=20.0, ingredients="2 Scheiben Vollkornbrot, 1 Avocado, 80g Kidneybohnen, 100g Kirschtomaten", instructions="1. Den Backofen auf 180°C vorheizen. 2. 100g Kirschtomaten waschen, halbieren, mit 1 TL Olivenöl, Salz und Pfeffer vermengen und 10 Minuten backen. 3. 80g Kidneybohnen abgießen und abspülen. 4. Die Avocado halbieren, entkernen und das Fruchtfleisch mit einer Gabel zerdrücken, mit Salz und Limettensaft würzen. 5. 2 Scheiben Vollkornbrot toasten und mit der Avocado-Creme bestreichen. 6. Bohnen und Tomaten darauf anrichten, mit Koriander bestreuen."),
        Recipe(name="Quinoa-Bananen-Porridge", category="fit", kcal=400, protein=18.0, carbs=65.0, fat=8.0, ingredients="60g Quinoa, 200ml Milch, 1 Banane, 1 EL Honig", instructions="1. 60g Quinoa in einem Sieb kalt abspülen. 2. Die Quinoa mit 200ml Milch in einem Topf aufkochen und bei niedriger Hitze 15 Minuten köcheln lassen. 3. Eine Banane schälen und mit einer Gabel zerdrücken. 4. Die zerdrückte Banane und 1 EL Honig unter den Quinoa rühren. 5. Mit 1 TL Zimt würzen und 2 Minuten weiterköcheln. 6. In eine Schale geben und mit Bananenscheiben und Mandeln toppen."),
        Recipe(name="Carrot-Cake-Baked-Oats", category="fit", kcal=390, protein=28.0, carbs=55.0, fat=10.0, ingredients="50g Haferflocken, 1 Ei, 1 Karotte, 25g Whey Vanille", instructions="1. Den Backofen auf 180°C Umluft vorheizen. 2. 50g Haferflocken, 1 Ei, 25g Whey Vanille, 100ml Milch und 1 TL Backpulver verrühren. 3. Eine Karotte schälen und fein reiben, unter den Teig heben. 4. 1 TL Zimt und 1 EL Honig zugeben. 5. Den Teig in eine gefettete Auflaufform geben. 6. 20-25 Minuten backen, mit 2 EL Skyr toppen und mit Walnüssen bestreuen."),
        Recipe(name="Powerfrühstück-Quark-Obst", category="lose", kcal=310, protein=35.0, carbs=30.0, fat=3.0, ingredients="250g Magerquark, 100g Beeren, 1 EL Leinsamen", instructions="1. 250g Magerquark in eine Schüssel geben und glatt rühren. 2. 100g gemischte Beeren waschen. 3. 1 EL Leinsamen in einer trockenen Pfanne kurz anrösten. 4. Die Beeren unter den Quark heben. 5. Mit Leinsamen bestreuen. 6. Nach Wunsch mit 1 TL Honig oder Stevia süßen."),
        Recipe(name="Omega-3-Quarkcreme", category="fit", kcal=350, protein=30.0, carbs=22.0, fat=16.0, ingredients="200g Quark, 1 EL Leinöl, 50g Walnüsse, 100g Beeren", instructions="1. 200g Quark in einer Schüssel glatt rühren. 2. 1 EL Leinöl und 1 TL Honig unterrühren. 3. 50g Walnüsse grob hacken. 4. 100g Beeren waschen. 5. Die Quarkcreme in eine Schale geben. 6. Mit Walnüssen und Beeren toppen und servieren."),
        
        // --- MITTAGESSEN ---
        Recipe(name="Römerpfanne", category="fit", kcal=450, protein=40.0, carbs=20.0, fat=25.0, ingredients="200g Hähnchen, 1 Zucchini, 1 Paprika, 100g Kirschtomaten, 1 EL Olivenöl", instructions="1. 200g Hähnchenbrust in Streifen schneiden, mit Salz, Pfeffer und Paprikapulver würzen. 2. 1 Zucchini waschen und in Scheiben schneiden, 1 Paprika entkernen und in Streifen schneiden. 3. 1 EL Olivenöl in einer Pfanne erhitzen, das Hähnchen 5 Minuten anbraten und herausnehmen. 4. Das Gemüse im Bratensatz 6 Minuten braten. 5. 100g Kirschtomaten halbieren und 3 Minuten mitbraten. 6. Hähnchen zurückgeben, mit Kräutern bestreuen und servieren."),
        Recipe(name="Cleaner Fitnessdöner", category="fit", kcal=480, protein=38.0, carbs=40.0, fat=18.0, ingredients="150g Hähnchen, 1 Vollkornfladenbrot, Salat, Gurke, 2 EL Joghurt", instructions="1. 150g Hähnchenbrust in dünne Streifen schneiden, mit Salz, Pfeffer, Paprika und 1 TL Kreuzkümmel würzen. 2. 1 TL Öl in einer Pfanne erhitzen und das Hähnchen 6 Minuten scharf braten. 3. Salat waschen, Gurke in Scheiben schneiden, eine Zwiebel in Ringe schneiden. 4. 2 EL Joghurt mit 1 Knoblauchzehe und 1 TL Zitronensaft verrühren. 5. Das Fladenbrot erwärmen und aufschneiden. 6. Mit Salat, Gurke, Zwiebel, Hähnchen und Joghurt-Sauce füllen."),
        Recipe(name="Quinoa-Thunfisch-Tomate", category="fit", kcal=420, protein=32.0, carbs=50.0, fat=12.0, ingredients="80g Quinoa, Dose Thunfisch, 3 Tomaten, 1 EL Olivenöl", instructions="1. 80g Quinoa abspülen und mit 160ml Wasser und 1 Prise Salz 15 Minuten quellen lassen. 2. Die Dose Thunfisch abgießen. 3. 3 Tomaten würfeln, eine halbe Gurke würfeln. 4. 1 EL Olivenöl mit 1 EL Zitronensaft, Salz und Pfeffer verrühren. 5. Quinoa, Thunfisch und Gemüse vermengen. 6. Mit dem Dressing übergießen und mit Petersilie bestreuen."),
        Recipe(name="Zucchini-Lasagne", category="lose", kcal=380, protein=35.0, carbs=15.0, fat=20.0, ingredients="2 Zucchini, 150g Rinderhack, 200ml Tomatensauce, 100g Mozzarella-Light", instructions="1. Den Backofen auf 180°C Umluft vorheizen. 2. 2 Zucchini längs in dünne Scheiben hobeln. 3. 150g Rinderhack mit Salz und Pfeffer würzen und 5 Minuten braten. 4. 200ml Tomatensauce mit Oregano zum Hack geben. 5. Abwechselnd Zucchini-Scheiben, Hack-Sauce und Mozzarella in eine Auflaufform schichten. 6. 25-30 Minuten backen, bis der Käse goldbraun ist."),
        Recipe(name="Muskel-Salat", category="build", kcal=480, protein=45.0, carbs=18.0, fat=26.0, ingredients="150g Hähnchen, 1 Ei, 50g Feta, Salat, 1 Avocado", instructions="1. 150g Hähnchenbrust mit Salz und Pfeffer würzen und 6 Minuten pro Seite braten, in Streifen schneiden. 2. 1 Ei hart kochen (8 Minuten), pellen und vierteln. 3. 50g Feta zerbröseln. 4. Eine Avocado in Scheiben schneiden. 5. 150g gemischten Salat waschen. 6. Alles auf einem Teller anrichten, mit 2 EL Balsamico-Dressing servieren."),
        Recipe(name="Kichererbsen-Pfanne", category="fit", kcal=440, protein=22.0, carbs=50.0, fat=16.0, ingredients="Dose Kichererbsen, 1 Zucchini, 1 Paprika, 1 EL Tahini", instructions="1. Die Dose Kichererbsen abgießen und abspülen. 2. 1 Zucchini und 1 Paprika in Würfel schneiden. 3. 1 EL Olivenöl erhitzen, das Gemüse 5 Minuten braten. 4. Die Kichererbsen zugeben und 5 Minuten mitbraten. 5. 1 EL Tahini mit 2 EL Wasser und 1 TL Zitronensaft verrühren. 6. Das Gemüse mit der Tahini-Sauce beträufeln und mit Petersilie servieren."),
        Recipe(name="Low-Carb-Buddha-Bowl", category="lose", kcal=390, protein=35.0, carbs=18.0, fat=22.0, ingredients="150g Lachs, 100g Brokkoli, 1 Avocado, 50g Rucola", instructions="1. 150g Lachs mit Zitronensaft, Salz und Pfeffer würzen. 2. 1 TL Öl erhitzen und den Lachs 4 Minuten pro Seite braten. 3. 100g Brokkoli in Röschen teilen und 5 Minuten dämpfen. 4. Eine Avocado in Scheiben schneiden. 5. 50g Rucola waschen. 6. Alles in einer Bowl anrichten und mit 2 EL Tahini-Dressing beträufeln."),
        Recipe(name="Bohnen-Hack-Pfanne", category="build", kcal=580, protein=42.0, carbs=45.0, fat=22.0, ingredients="150g Rinderhack, Dose Kidneybohnen, 1 Zwiebel, 100g Mais", instructions="1. 150g Rinderhack mit Salz, Pfeffer und 1 TL Kreuzkümmel würzen. 2. 1 Zwiebel hacken und in 1 TL Öl glasig dünsten. 3. Das Hack zugeben und 5 Minuten krümelig braten. 4. Die Dose Kidneybohnen und 100g Mais abgießen und zugeben. 5. 100ml Brühe angißen und 10 Minuten köcheln lassen. 6. Mit Koriander bestreuen und servieren."),
        Recipe(name="Rote-Bete-Salat-High-Protein", category="fit", kcal=340, protein=28.0, carbs=25.0, fat=16.0, ingredients="200g vorgegarte Rote Bete, 100g Hüttenkäse, 50g Walnüsse, Rucola", instructions="1. 200g Rote Bete in Würfel schneiden. 2. 100g Hüttenkäse in einer Schüssel mit 1 TL Meerrettich verrühren. 3. 50g Walnüsse grob hacken. 4. 50g Rucola waschen. 5. Rote Bete, Rucola und Hüttenkäse auf einem Teller anrichten. 6. Mit Walnüssen bestreuen und mit 1 EL Balsamico beträufeln."),
        
        // --- ABENDESSEN ---
        Recipe(name="Gefüllte Hähnchenbrust mit Feta", category="fit", kcal=420, protein=45.0, carbs=8.0, fat=22.0, ingredients="200g Hähnchenbrust, 50g Feta, 100g Spinat, 1 EL Öl", instructions="1. Den Backofen auf 200°C Umluft vorheizen. 2. 100g Spinat waschen, 1 Zehe Knoblauch hacken. 3. 1 TL Öl erhitzen, Knoblauch und Spinat 2 Minuten zusammenfallen lassen. 4. 50g Feta zerbröseln und mit dem Spinat vermischen. 5. Das Hähnchen seitlich einschneiden, mit der Spinat-Feta-Mischung füllen und mit Zahnstochern fixieren. 6. Das Hähnchen mit Öl bepinseln und 25-30 Minuten backen, bis es goldbraun ist."),
        Recipe(name="High-Protein-One-Pot-Pasta", category="build", kcal=560, protein=40.0, carbs=75.0, fat=12.0, ingredients="100g Vollkornnudeln, 150g Hähnchen, 200ml Tomatensauce, 1 Zucchini", instructions="1. 150g Hähnchenbrust in Würfel schneiden. 2. 100g Vollkornnudeln, das Hähnchen, 200ml Tomatensauce und 300ml Wasser in einen Topf geben. 3. 1 Zucchini würfeln und zugeben. 4. Mit Salz, Oregano und Chili würzen. 5. Bei starker Hitze aufkochen, dann 12 Minuten köcheln, bis die Nudeln gar sind. 6. Mit Parmesan servieren."),
        Recipe(name="Asia-Nudeln-Hähnchen", category="fit", kcal=520, protein=38.0, carbs=65.0, fat=12.0, ingredients="100g Mie-Nudeln, 150g Hähnchen, 1 Paprika, 2 EL Sojasauce", instructions="1. 100g Mie-Nudeln mit kochendem Wasser übergießen und 4 Minuten ziehen lassen, abgießen. 2. 150g Hähnchen in Streifen schneiden. 3. 1 EL Sesamöl im Wok erhitzen, das Hähnchen 4 Minuten braten, herausnehmen. 4. 1 Paprika und 1 Karotte in Streifen schneiden und 3 Minuten im Wok braten. 5. 2 EL Sojasauce, 1 TL Honig und 1cm Ingwer zugeben. 6. Nudeln und Hähnchen zurückgeben, vermengen und servieren."),
        Recipe(name="Lachs-Ofengemüse", category="fit", kcal=480, protein=38.0, carbs=18.0, fat=28.0, ingredients="200g Lachs, 200g Brokkoli, 1 Zucchini, 1 EL Olivenöl", instructions="1. Den Backofen auf 200°C Umluft vorheizen. 2. 200g Lachs mit Zitronensaft, Salz und Pfeffer würzen. 3. 200g Brokkoli in Röschen, 1 Zucchini in Scheiben schneiden. 4. Gemüse auf ein Backblech geben, mit 1 EL Olivenöl beträufeln und salzen. 5. Den Lachs darauf legen. 6. 18-20 Minuten backen, mit Dill bestreuen und servieren."),
        Recipe(name="High-Protein-Käsespätzle", category="build", kcal=620, protein=42.0, carbs=65.0, fat=22.0, ingredients="200g Spätzle, 150g Rinderhack, 100g Käse-Light, 1 Zwiebel", instructions="1. Die Spätzle nach Packungsanweisung zubereiten. 2. 150g Rinderhack mit Salz und Pfeffer würzen und 5 Minuten braten. 3. Eine Zwiebel in Ringe schneiden und in 1 TL Öl karamellisieren. 4. 100g Käse-Light reiben. 5. Spätzle, Hack und die Hälfte des Käses in einer Auflaufform schichten. 6. Mit restlichem Käse und Zwiebeln toppen, 10 Minuten bei 180°C überbacken."),
        Recipe(name="Low-Carb-Bauerntopf", category="lose", kcal=380, protein=35.0, carbs=20.0, fat=18.0, ingredients="150g Rinderhack, 200g Zucchini, 200g Blumenkohl, 200ml Tomatensauce", instructions="1. 150g Rinderhack 5 Minuten krümelig braten. 2. 1 Zwiebel hacken und zugeben. 3. 200g Zucchini und 200g Blumenkohl in kleine Stücke schneiden. 4. Das Gemüse und 200ml Tomatensauce zum Hack geben. 5. Mit Salz, Pfeffer und Majoran würzen und 15 Minuten köcheln. 6. Mit Petersilie bestreuen und servieren."),
        Recipe(name="Rindergulasch-Protein", category="build", kcal=520, protein=55.0, carbs=15.0, fat=28.0, ingredients="250g Rindergulasch, 1 Zwiebel, 200ml Brühe, 1 EL Paprikapulver", instructions="1. 250g Rindergulasch trocken tupfen. 2. 1 EL Öl im Schmortopf erhitzen und das Fleisch scharf anbraten. 3. 1 Zwiebel und 2 Knoblauchzehen hacken und zugeben. 4. 1 EL Tomatenmark und 1 EL Paprikapulver einrühren. 5. Mit 200ml Brühe ablöschen und 1 TL Kümmel zugeben. 6. 1,5 Stunden bei niedriger Hitze schmoren lassen, bis das Fleisch zart ist."),
        Recipe(name="Hackbällchen-Senf-Sauce", category="fit", kcal=480, protein=40.0, carbs=20.0, fat=28.0, ingredients="200g Rinderhack, 1 Ei, 2 EL Senf, 100ml Brühe", instructions="1. 200g Rinderhack mit 1 Ei, 1 EL Senf, Salz und Pfeffer vermengen. 2. Kleine Bällchen formen. 3. 1 TL Öl erhitzen und die Bällchen rundherum 8 Minuten braten, herausnehmen. 4. 1 Zwiebel hacken und im Bratensatz glasig dünsten. 5. 100ml Brühe, 1 EL Senf und 2 EL Schmand-Light zugeben, aufkochen. 6. Die Bällchen zurückgeben und 5 Minuten in der Sauce ziehen lassen."),
        Recipe(name="High-Protein-Pizza", category="build", kcal=450, protein=42.0, carbs=12.0, fat=26.0, ingredients="200g Hähnchenbrust, 50g Tomatensauce, 80g Mozzarella-Light, Oregano", instructions="1. Den Backofen auf 200°C Umluft vorheizen. 2. 200g Hähnchenbrust in dünne Scheiben schneiden oder klopfen. 3. Die Hähnchenscheiben auf ein Backblech legen. 4. Mit 50g Tomatensauce bestreichen, mit Salz und Oregano würzen. 5. 80g Mozzarella-Light darauf verteilen. 6. 15 Minuten backen, bis der Käse geschmolzen ist."),
        Recipe(name="Zucchini-Karotten-Nudeln-Hähnchen", category="fit", kcal=410, protein=38.0, carbs=20.0, fat=20.0, ingredients="2 Zucchini, 2 Karotten, 150g Hähnchen, 1 EL Pesto", instructions="1. 150g Hähnchenbrust würfeln, mit Salz und Pfeffer würzen. 2. 1 TL Öl erhitzen und das Hähnchen 5 Minuten braten, herausnehmen. 3. 2 Zucchini und 2 Karotten mit einem Spiralschneider in Nudelform bringen. 4. Die Gemüsenudeln 2 Minuten in der Pfanne anbraten. 5. 1 EL Pesto-Light unterrühren. 6. Hähnchen zurückgeben, vermengen und mit Parmesan servieren."),
        
        // --- TRAINING / PRE-POST-WORKOUT ---
        Recipe(name="High-Protein-Kaiserschmarrn", category="build", kcal=480, protein=38.0, carbs=50.0, fat=14.0, ingredients="3 Eier, 50g Dinkelmehl, 200ml Milch, 25g Whey Vanille", instructions="1. 3 Eier trennen. 2. 50g Dinkelmehl, 200ml Milch, 25g Whey Vanille und die Eigelb verrühren. 3. 1 Prise Salz zugeben. 4. Das Eiweiß steif schlagen und unterheben. 5. 1 TL Butter in einer Pfanne erhitzen, den Teig hineingeben und bei mittlerer Hitze stocken lassen. 6. In Stücke reißen, mit 1 EL Rosinen bestreuen und mit Apfelmus servieren."),
        Recipe(name="Protein-Pancakes", category="build", kcal=420, protein=35.0, carbs=40.0, fat=12.0, ingredients="40g Hafermehl, 30g Whey, 2 Eier, 100ml Milch", instructions="1. 40g Hafermehl, 30g Whey, 2 Eier, 100ml Milch und 1 TL Backpulver zu einem glatten Teig verrühren. 2. 1 TL Kokosöl in einer Pfanne erhitzen. 3. Kleine Pancakes aus dem Teig formen und 2-3 Minuten pro Seite backen. 4. Mit frischen Beeren und 1 EL Skyr toppen. 5. Nach Wunsch mit Ahornsirup servieren. 6. Ideal vor oder nach dem Training."),
        Recipe(name="High-Protein-Snickers-Bowl", category="build", kcal=450, protein=35.0, carbs=40.0, fat=18.0, ingredients="200g Skyr, 1 EL Erdnussmus, 1 EL Kakaonibs, 1 Banane", instructions="1. 200g Skyr in eine Schale geben. 2. 1 EL Erdnussmus darauf geben. 3. Eine Banane in Scheiben schneiden und darauf anrichten. 4. 1 EL Kakaonibs und 1 EL gehackte Erdnüsse darüber streuen. 5. Nach Wunsch mit 1 TL Honig beträufeln. 6. Ideal als Post-Workout-Meal."),
        Recipe(name="Muskelaufbau-Shake", category="build", kcal=550, protein=50.0, carbs=60.0, fat=12.0, ingredients="40g Whey, 1 Banane, 200ml Milch, 1 EL Erdnussmus, 30g Haferflocken", instructions="1. 40g Whey Protein, 1 Banane, 200ml Milch und 1 EL Erdnussmus in den Mixer geben. 2. 30g Haferflocken zugeben. 3. 1 TL Honig zugeben. 4. 60 Sekunden auf höchster Stufe cremig mixen. 5. In einen Shaker füllen. 6. Direkt nach dem Training trinken."),
        Recipe(name="Flinke-Frittata", category="fit", kcal=360, protein=30.0, carbs=8.0, fat=24.0, ingredients="3 Eier, 100g Champignons, 50g Kirschtomaten, 30g Käse", instructions="1. Den Backofen auf 180°C vorheizen. 2. 100g Champignons in Scheiben schneiden, 50g Kirschtomaten halbieren. 3. 1 TL Öl in einer ofenfesten Pfanne erhitzen, Pilze und Tomaten 3 Minuten braten. 4. 3 Eier mit Salz, Pfeffer und 1 EL Milch verquirlen. 5. Die Eier über das Gemüse gießen, 30g Käse darauf reiben. 6. Die Pfanne in den Ofen geben und 10-12 Minuten backen, bis die Frittata goldbraun ist.")
     )
 }
 
